// Unit 29: Die Debatte
// Level: B2

const UNIT_29 =
{n:29,lang:"de",srcLang:"en",track:"v2",title:"Die Debatte",sub:"Einerseits... andererseits",icon:"⚖️",level:"B2.1",color:"#7B5EE8",lessons:[
{id:"deu_r29l1",title:"Integration und Zusammenleben",icon:"\uD83C\uDFDB\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Integration und Zusammenleben",desc:"A community hall in Berlin. A panel discussion about integration begins. Verumius sits in the audience, notebook ready. Learn the key words of German politics and democracy.",goals:["Learn 20 words from politics and democracy","Discover the world of the German panel discussion","Join Verumius in his first public debate"]},
{type:"teach",trg:"die Debatte",src:"the debate",pos:"noun",gender:"f",note:"From French 'debat.' Die Debatte is the formal arena of ideas.\nIn the Bundestag, debates follow strict rules.",example:"A: Wie war die Debatte gestern?\nB: Sehr lebhaft. Alle hatten starke Meinungen.\nA: Gab es eine klare Debatte?\nB: Ja, die Debatte war fair und respektvoll.",exampleSrc:"A: How was the debate yesterday?\nB: Very lively. Everyone had strong opinions.\nA: Was there a clear debate?\nB: Yes, the debate was fair and respectful.",funFact:"Bundestag debates follow strict rules: speaking time, topic order, right to reply. The word came via French 'debattre' (to fight/discuss). A Debatte is not a fight. It is structured disagreement."},
{type:"teach",trg:"die Demokratie",src:"democracy",pos:"noun",gender:"f",note:"From Greek 'demos' (people) + 'kratia' (rule).\nArticle 20 of the Grundgesetz enshrines it.",example:"A: Was bedeutet Demokratie f\u00fcr dich?\nB: Dass das Volk entscheidet.\nA: Ist die Demokratie in Gefahr?\nB: Nein, aber wir m\u00fcssen sie sch\u00fctzen.",exampleSrc:"A: What does democracy mean to you?\nB: That the people decide.\nA: Is democracy in danger?\nB: No, but we must protect it.",funFact:"Germany's Basic Law was written in 1949 to ensure democracy could never be destroyed again. Article 20 declares: 'Alle Staatsgewalt geht vom Volke aus.' The Greek roots say it all: demos (people) + kratia (rule)."},
{type:"teach",trg:"die Partei",src:"the (political) party",pos:"noun",gender:"f",note:"From Latin 'pars' (part). Germany has a multi-party system.\nCoalition governments are standard.",example:"A: Welche Partei unterst\u00fctzt du?\nB: Ich w\u00e4hle jede Partei, die mich \u00fcberzeugt.\nA: Gibt es viele Parteien?\nB: Ja, sechs gro\u00dfe Parteien im Bundestag.",exampleSrc:"A: Which party do you support?\nB: I vote for whichever party convinces me.\nA: Are there many parties?\nB: Yes, six major parties in the Bundestag.",funFact:"Germany has six major parties in the Bundestag: CDU, SPD, Gruene, FDP, Linke, AfD. A single party almost never wins alone, so coalitions are the norm. The Latin root 'pars' (part) fits perfectly: every Partei is just one part of the whole."},
{type:"teach",trg:"der Politiker",src:"the politician (male)",pos:"noun",gender:"m",note:"From Greek 'politikos.' German politicians navigate\ncoalition politics, federalism, and the EU simultaneously.",example:"A: Kennst du den Politiker?\nB: Ja, er ist Abgeordneter im Bundestag.\nA: Ist er ein guter Politiker?\nB: Er vertritt seine W\u00e4hler gut.",exampleSrc:"A: Do you know the politician?\nB: Yes, he is a member of the Bundestag.\nA: Is he a good politician?\nB: He represents his voters well.",funFact:"German politicians juggle three levels at once: coalition politics, federalism across 16 Bundeslaender, and the EU. The word goes back to Greek 'politikos.' 'Berufspolitiker' (career politician) can sound neutral or slightly critical."},
{type:"mc",q:"Deutschland hat ein Mehrparteiensystem. Was folgt daraus f\u00fcr die Regierungsbildung?",opts:["Regierungen sind fast immer Koalitionen aus mehreren Parteien","Eine Partei gewinnt immer allein die absolute Mehrheit","Es gibt nur zwei gro\u00dfe Parteien im Bundestag","Der Kanzler wird direkt vom Volk gew\u00e4hlt"],ans:"Regierungen sind fast immer Koalitionen aus mehreren Parteien",hint:"Germany has six major parties. A single party almost never wins enough seats to govern alone. Politics is always about compromise."},
{type:"teach",trg:"die Politikerin",src:"the politician (female)",pos:"noun",gender:"f",note:"Politiker + '-in.' Die Politikerin.\nGermany had its first female chancellor in 2005.",example:"A: Wer ist diese Politikerin?\nB: Eine bekannte Abgeordnete.\nA: Was fordert die Politikerin?\nB: Mehr Gleichberechtigung in der Politik.",exampleSrc:"A: Who is this politician?\nB: A well-known member of parliament.\nA: What does the politician demand?\nB: More equality in politics.",funFact:"Politiker + '-in.' Germany had its first female chancellor (Kanzlerin) in 2005. The feminine form of political titles is now standard in all German media and official documents."},
{type:"teach",trg:"die Regierung",src:"the government",pos:"noun",gender:"f",note:"From 'regieren' (to govern). Germany has 17 governments\nsimultaneously: 1 federal + 16 state.",example:"A: Was macht die Regierung gegen den Klimawandel?\nB: Die Regierung hat neue Gesetze beschlossen.\nA: Ist die Regierung popul\u00e4r?\nB: Die Regierung hat viele Kritiker.",exampleSrc:"A: What is the government doing about climate change?\nB: The government has passed new laws.\nA: Is the government popular?\nB: The government has many critics.",funFact:"Did you know Germany has 17 governments running at the same time? One federal, plus one for each of the 16 Bundeslaender. The word comes from 'regieren' (to govern)."},
{type:"teach",trg:"die Opposition",src:"the opposition",pos:"noun",gender:"f",note:"From Latin 'oppositio' (placing against). In the Bundestag,\nthe opposition holds the government accountable.",example:"A: Was sagt die Opposition?\nB: Die Opposition kritisiert den Gesetzentwurf.\nA: Ist die Opposition stark?\nB: Ja, sie hat viele Abgeordnete.",exampleSrc:"A: What does the opposition say?\nB: The opposition criticizes the bill.\nA: Is the opposition strong?\nB: Yes, they have many members of parliament.",funFact:"In the Bundestag, opposition is not just tolerated, it is institutionalized. Opposition parties formally hold the government accountable. The Latin root 'oppositio' means placing against. 'Konstruktive Opposition' is the gold standard."},
{type:"teach",trg:"das Parlament",src:"the parliament",pos:"noun",gender:"n",note:"From French 'parlement,' from 'parler' (to speak).\nThe Bundestag has over 700 members.",example:"A: Wie viele Abgeordnete hat das Parlament?\nB: \u00dcber 700 im Bundestag.\nA: Tagt das Parlament jeden Tag?\nB: Nein, das Parlament hat Sitzungswochen.",exampleSrc:"A: How many members does the parliament have?\nB: Over 700 in the Bundestag.\nA: Does parliament meet every day?\nB: No, parliament has session weeks.",funFact:"The Bundestag is one of the world's largest parliaments, with over 700 members. Its Reichstag building has a glass dome symbolizing transparency. The word traces to French 'parler' (to speak): parliament is literally a place for speaking."},
{type:"fb",s:"Die {1} kritisiert den Gesetzentwurf und h\u00e4lt die Regierung zur Rechenschaft.",a:["Opposition"],opts:["Koalition","Opposition","Regierung","Fraktion"],hint:"The group in parliament that challenges the governing party. From Latin 'oppositio' (placing against).",sSrc:"The opposition criticizes the bill and holds the government accountable."}
]},
{id:"deu_r29l1b",title:"Integration und Zusammenleben (Teil 2)",icon:"\uD83C\uDFDB\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Integration und Zusammenleben (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Bundestag",src:"the Bundestag (German federal parliament)",pos:"noun",gender:"m",note:"'Bund' (federation) + 'Tag' (day/assembly).\nMeets in the Reichstag building in Berlin.",example:"A: Was passiert heute im Bundestag?\nB: Eine Abstimmung \u00fcber ein neues Gesetz.\nA: Wer sitzt im Bundestag?\nB: Die gew\u00e4hlten Abgeordneten aller Parteien.",exampleSrc:"A: What is happening in the Bundestag today?\nB: A vote on a new law.\nA: Who sits in the Bundestag?\nB: The elected members of all parties.",funFact:"'Bund' (federation) + 'Tag' (day/assembly). Originally 'Tag' meant 'assembly' (same root as English 'diet' in its political sense). The Bundestag meets in the Reichstag building in Berlin. It is the heart of German democracy."},
{type:"teach",trg:"der Standpunkt",src:"the viewpoint, the position",pos:"noun",gender:"m",note:"'Stand' (standing) + 'Punkt' (point). The point where\nyou plant your feet in a debate.",example:"A: Was ist Ihr Standpunkt zu diesem Thema?\nB: Mein Standpunkt ist klar: Integration braucht beide Seiten.\nA: K\u00f6nnen Sie Ihren Standpunkt begr\u00fcnden?\nB: Nat\u00fcrlich. Ich vertrete meinen Standpunkt mit Fakten.",exampleSrc:"A: What is your viewpoint on this topic?\nB: My position is clear: integration needs both sides.\nA: Can you justify your viewpoint?\nB: Of course. I support my position with facts.",funFact:"'Stand' (standing) + 'Punkt' (point). Literally the point where you stand. 'Meinen Standpunkt vertreten' (to represent my point of view). Where you plant your feet in a debate."},
{type:"teach",trg:"die Meinungsverschiedenheit",src:"the difference of opinion",pos:"noun",gender:"f",note:"'Meinung' (opinion) + 'Verschiedenheit' (difference).\nNot a fight. Just: our opinions are different.",example:"A: Gibt es Meinungsverschiedenheiten im Team?\nB: Ja, aber wir diskutieren respektvoll.\nA: Ist eine Meinungsverschiedenheit schlimm?\nB: Nein, sie ist normal und gesund.",exampleSrc:"A: Are there differences of opinion in the team?\nB: Yes, but we discuss respectfully.\nA: Is a difference of opinion bad?\nB: No, it is normal and healthy.",funFact:"'Meinung' (opinion) + 'Verschiedenheit' (difference). One of those beautifully precise German compounds. Not a fight, not a conflict. Just: our opinions are different. Clinical and civilized."},
{type:"teach",trg:"politisch",src:"political",pos:"adj",gender:null,note:"From Greek 'politikos.' 'Politische Bildung' (political education)\nis a school subject in Germany.",example:"A: Interessierst du dich f\u00fcr politische Themen?\nB: Ja, politische Bildung ist wichtig.\nA: Ist das ein politisches Problem?\nB: Ja, es betrifft die ganze Gesellschaft.",exampleSrc:"A: Are you interested in political topics?\nB: Yes, political education is important.\nA: Is that a political problem?\nB: Yes, it affects the whole society.",funFact:"'Politische Bildung' (political education) is a mandatory school subject in Germany. Students learn HOW democracy works, not just that it exists. The adjective traces back to Greek 'politikos.'"},
{type:"teach",trg:"demokratisch",src:"democratic",pos:"adj",gender:null,note:"Demokratie + '-isch.' 'Demokratische Grundwerte'\nare enshrined in the Grundgesetz.",example:"A: Ist Deutschland ein demokratisches Land?\nB: Ja, demokratische Wahlen sind die Grundlage.\nA: Was sind demokratische Werte?\nB: Freiheit, Gleichheit und Menschenw\u00fcrde.",exampleSrc:"A: Is Germany a democratic country?\nB: Yes, democratic elections are the foundation.\nA: What are democratic values?\nB: Freedom, equality, and human dignity.",funFact:"Demokratie + '-isch.' 'Demokratische Grundwerte' (democratic basic values) are enshrined in the Grundgesetz. The word carries weight in Germany, where democracy was hard-won and once lost."},
{type:"match",pairs:[{trg:"der Standpunkt",src:"the viewpoint, the position"},{trg:"die Meinungsverschiedenheit",src:"the difference of opinion"},{trg:"politisch",src:"political"},{trg:"demokratisch",src:"democratic"}]},
{type:"teach",trg:"parlamentarisch",src:"parliamentary",pos:"adj",gender:null,note:"Parlament + '-isch.' 'Parlamentarische Anfrage' is how\nopposition politicians hold the government accountable.",example:"A: Was ist eine parlamentarische Anfrage?\nB: Eine offizielle Frage an die Regierung.\nA: Muss die Regierung antworten?\nB: Ja, jede parlamentarische Anfrage wird beantwortet.",exampleSrc:"A: What is a parliamentary question?\nB: An official question to the government.\nA: Must the government answer?\nB: Yes, every parliamentary question is answered.",funFact:"Parlament + '-isch.' 'Parlamentarische Anfrage' (parliamentary question) is how opposition politicians hold the government accountable. Every question must be answered officially."},
{type:"teach",trg:"kontrovers",src:"controversial",pos:"adj",gender:null,note:"From Latin 'controversus' (turned against). Calling something\n'kontrovers' is neutral: it means people disagree.",example:"A: Ist das Thema kontrovers?\nB: Ja, sehr kontrovers. Die Meinungen gehen auseinander.\nA: Warum ist es so kontrovers?\nB: Weil es jeden betrifft.",exampleSrc:"A: Is the topic controversial?\nB: Yes, very controversial. Opinions differ.\nA: Why is it so controversial?\nB: Because it affects everyone.",funFact:"Calling something 'kontrovers' in German is neutral, not negative. It simply means people disagree, and that is democracy. The Latin root 'controversus' literally means turned against each other."},
{type:"mc",q:"Das Thema ist kontrovers, die Meinungen gehen auseinander. Was bedeutet 'kontrovers'?",opts:["Langweilig und insgesamt unwichtig","Alle Beteiligten sind sich einig dar\u00fcber","Menschen sind sich uneinig dar\u00fcber","Es wurde schon l\u00e4ngst entschieden"],ans:"Menschen sind sich uneinig dar\u00fcber",hint:"From Latin 'controversus' (turned against). Calling something kontrovers is neutral: it simply means people disagree."},
{type:"teach",trg:"umstritten",src:"contested, disputed",pos:"adj",gender:null,note:"'Um' (around) + 'stritten' (fought). More negative than\n'kontrovers.' Something umstritten has active opponents.",example:"A: Der Vorschlag ist umstritten.\nB: Ja, viele sind dagegen.\nA: Warum ist die Entscheidung so umstritten?\nB: Weil sie nicht alle \u00fcberzeugt.",exampleSrc:"A: The proposal is contested.\nB: Yes, many are against it.\nA: Why is the decision so contested?\nB: Because it does not convince everyone.",funFact:"'Um' (around) + 'stritten' (fought). The um- prefix suggests fighting all around something. More negative than kontrovers. Something umstritten has active opponents."},
{type:"teach",trg:"kritisieren",src:"to criticize",pos:"verb",gender:null,note:"From Greek 'kritikos' (able to judge). 'Konstruktive Kritik'\n(constructive criticism) is valued in German culture.",example:"A: Die Opposition kritisiert den Entwurf.\nB: Was genau kritisieren sie?\nA: Sie kritisieren die hohen Kosten.\nB: Konstruktiv kritisieren ist wichtig.",exampleSrc:"A: The opposition criticizes the bill.\nB: What exactly do they criticize?\nA: They criticize the high costs.\nB: Constructive criticism is important.",funFact:"In German political culture, 'konstruktive Kritik' (constructive criticism) is valued. Pure negativity is not. The Greek root 'kritikos' means able to judge, and good criticism requires judgment, not just complaints."},
{type:"teach",trg:"\u00fcberzeugen",src:"to convince",pos:"verb",gender:null,note:"'\u00dcber' (over/completely) + 'zeugen' (to bear witness).\n'Mich \u00fcberzeugt das nicht' is polite skepticism.",example:"A: Hat dich die Rede \u00fcberzeugt?\nB: Nicht ganz. Mich \u00fcberzeugt das Argument nicht.\nA: Wie kann man dich \u00fcberzeugen?\nB: Mit Fakten und guten Beispielen.",exampleSrc:"A: Did the speech convince you?\nB: Not quite. The argument does not convince me.\nA: How can one convince you?\nB: With facts and good examples.",funFact:"'\u00dcber' (over/completely) + 'zeugen' (to bear witness). Literally: to completely witness something to someone. 'Mich \u00fcberzeugt das nicht' (That does not convince me) is polite skepticism."},
{type:"teach",trg:"unterst\u00fctzen",src:"to support",pos:"verb",gender:null,note:"'Unter' (under) + 'st\u00fctzen' (to prop up). Not separable.\nYou hold something up from beneath.",example:"A: Unterst\u00fctzt du diesen Vorschlag?\nB: Ja, ich unterst\u00fctze ihn voll.\nA: Wer unterst\u00fctzt die Reform?\nB: Die Koalition unterst\u00fctzt sie geschlossen.",exampleSrc:"A: Do you support this proposal?\nB: Yes, I fully support it.\nA: Who supports the reform?\nB: The coalition supports it unanimously.",funFact:"'Unter' (under) + 'st\u00fctzen' (to support). Literally to prop up from below. 'Ich unterst\u00fctze diesen Vorschlag' (I support this proposal). Not separable. The under-support image: you hold something up from beneath."},
{type:"fb",s:"Hat dich die Rede {1}? Nicht ganz, die Argumente waren zu schwach.",a:["\u00fcberzeugt"],opts:["unterst\u00fctzt","kritisiert","verteidigt","\u00fcberzeugt"],hint:"The Partizip II of the verb meaning 'to convince.' From \u00fcber (over) + zeugen (to bear witness).",sSrc:"Did the speech convince you? Not quite, the arguments were too weak."},
{type:"teach",trg:"verteidigen",src:"to defend",pos:"verb",gender:null,note:"From Middle High German 'verteidingen' (to settle in court).\nOriginally a legal term that moved into everyday language.",example:"A: Verteidigen Sie Ihren Standpunkt?\nB: Ja, ich verteidige ihn mit Fakten.\nA: Kann man diese Position verteidigen?\nB: Ja, sie l\u00e4sst sich gut verteidigen.",exampleSrc:"A: Are you defending your position?\nB: Yes, I defend it with facts.\nA: Can this position be defended?\nB: Yes, it can be well defended.",funFact:"Originally a courtroom word in Middle High German ('verteidingen' meant to settle in court), it migrated into everyday language. Now you defend positions, rights, and people. 'Seinen Standpunkt verteidigen' (to defend one's position)."},
{type:"mc",q:"Das Banner sagt 'Integration und Zusammenleben.' Die Moderatorin sagt, die Standpunkte sind verschieden. Was ist ein Standpunkt?",opts:["Ein Blickwinkel oder eine Position","Eine stehende Ovation des Publikums","Ein wichtiges Debattenthema oder Streitpunkt","Eine bestimmte politische Partei"],ans:"Ein Blickwinkel oder eine Position",hint:"A compound noun: a spatial metaphor for where someone stands intellectually. It describes a personal attitude or viewpoint in a discussion."},
{type:"match",pairs:[{trg:"Debatte",src:"debate"},{trg:"Demokratie",src:"democracy"},{trg:"Regierung",src:"government"},{trg:"Bundestag",src:"German parliament"}]},
{type:"mc",q:"Was bedeutet 'der Standpunkt'?",opts:["the difference of opinion","the (political) party","the government","the viewpoint, the position"],ans:"the viewpoint, the position",hint:"Compound: Stand (standing) + Punkt (point). The point where you stand intellectually."},
{type:"fb",s:"Wie sagt man 'the difference of opinion' auf Deutsch? {1}",a:["die Meinungsverschiedenheit"],opts:["der Politiker","die Partei","kritisieren","die Meinungsverschiedenheit"],hint:"Meinung (opinion) + Verschiedenheit (difference). A compound noun for disagreement.",sSrc:"How do you say 'the difference of opinion' in German?"},
{type:"mc",q:"Was bedeutet 'demokratisch'?",opts:["democratic","to convince","the opposition","the parliament"],ans:"democratic",hint:"A direct cognate from Greek demos (people) + kratos (power). Nearly identical in English."},
{type:"fb",s:"Was ist eine {1}e Anfrage?",a:["parlamentarisch"],opts:["unterst\\u00fctzen","die Meinungsverschiedenheit","der Politiker","parlamentarisch"],hint:"Adjective form of Parlament. Relating to the legislative assembly.",sSrc:"What is a parliamentary question?"},
{type:"mc",q:"Was bedeutet 'kritisieren'?",opts:["parliamentary","to criticize","political","to convince"],ans:"to criticize",hint:"Sounds like its English equivalent. From Greek krinein (to judge)."},
{type:"fb",s:"{1} Sie Ihren Standpunkt?",a:["verteidigen"],opts:["verteidigen","die Partei","politisch","der Politiker"],hint:"The verb a lawyer does in court: to defend. Also used in debates and sports.",sSrc:"Are you defending your position?"}
]},
{id:"deu_r29l2",title:"Argumente und Gegenargumente",icon:"\u2696\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Argumente und Gegenargumente",desc:"The language of parliament. Learn the key words for legislation, debates, and the structures of German democracy.",goals:["Learn 20 words from parliamentary language","Understand how German legislation works","Build your political vocabulary"]},
{type:"mc",q:"Haben die Parteien einen Kompromiss gefunden? Was ist ein Kompromiss in der deutschen Politik?",opts:["Die Ablehnung aller Vorschl\u00e4ge","Die vollst\u00e4ndige Zustimmung zu einem Vorschlag","Eine gemeinsame L\u00f6sung nach Verhandlungen beider Seiten","Eine einseitige Entscheidung der st\u00e4rksten Partei"],ans:"Eine gemeinsame L\u00f6sung nach Verhandlungen beider Seiten",hint:"From Latin 'compromissum' (mutual promise). Not weakness but political skill. The backbone of coalition politics."},
{type:"teach",trg:"das Gegenargument",src:"the counterargument",pos:"noun",gender:"n",note:"'Gegen' (against) + 'Argument.' German debate culture\nvalues having a strong Gegenargument ready.",example:"A: Haben Sie ein Gegenargument?\nB: Ja, mein Gegenargument ist einfach.\nA: Ist das Gegenargument stark?\nB: Ja, es widerlegt die These komplett.",exampleSrc:"A: Do you have a counterargument?\nB: Yes, my counterargument is simple.\nA: Is the counterargument strong?\nB: Yes, it completely refutes the thesis.",funFact:"'Gegen' (against) + 'Argument.' German debate culture values having a strong Gegenargument ready. 'Dazu habe ich ein Gegenargument' (I have a counterargument to that) is how you signal disagreement respectfully."},
{type:"teach",trg:"die Koalition",src:"the coalition",pos:"noun",gender:"f",note:"From Latin 'coalitio' (growing together). German governments\nare almost always coalitions of two or three parties.",example:"A: Welche Parteien bilden die Koalition?\nB: Drei Parteien in der aktuellen Koalition.\nA: Ist die Koalition stabil?\nB: Ja, aber Kompromisse sind n\u00f6tig.",exampleSrc:"A: Which parties form the coalition?\nB: Three parties in the current coalition.\nA: Is the coalition stable?\nB: Yes, but compromises are necessary.",funFact:"German governments are almost always coalitions, and the coalition agreement (Koalitionsvertrag) can be hundreds of pages long. The Latin root 'coalitio' means growing together, which is exactly what two or three parties must do before governing."},
{type:"teach",trg:"der Kompromiss",src:"the compromise",pos:"noun",gender:"m",note:"From Latin 'compromissum' (mutual promise).\nThe backbone of German coalition politics.",example:"A: Haben die Parteien einen Kompromiss gefunden?\nB: Ja, nach langen Verhandlungen.\nA: Ist ein Kompromiss Schw\u00e4che?\nB: Nein, ein Kompromiss ist politisches K\u00f6nnen.",exampleSrc:"A: Have the parties found a compromise?\nB: Yes, after long negotiations.\nA: Is a compromise weakness?\nB: No, a compromise is political skill.",funFact:"Coalition politics runs on compromise: 'einen Kompromiss finden' (to find a compromise) is what politicians do daily. Not weakness, but skill. Latin 'compromissum' literally meant a mutual promise."},
{type:"teach",trg:"die Fraktion",src:"the parliamentary group",pos:"noun",gender:"f",note:"From Latin 'fractio' (breaking). A parliamentary group\nof the same party that votes together.",example:"A: Wie gro\u00df ist die Fraktion?\nB: Die Fraktion hat 200 Abgeordnete.\nA: Stimmt die Fraktion immer geschlossen ab?\nB: Meistens. Fraktionszwang ist real.",exampleSrc:"A: How large is the parliamentary group?\nB: The parliamentary group has 200 members.\nA: Does the parliamentary group always vote together?\nB: Usually. Party discipline is real.",funFact:"The Fraktion votes together, debates internally, and presents a united front. 'Fraktionszwang' (party discipline) is real but unofficial. Surprisingly, the Latin root 'fractio' means breaking, the opposite of unity."},
{type:"fb",s:"Die Regierung ist fast immer eine {1} aus zwei oder drei Parteien.",a:["Koalition"],opts:["Koalition","Fraktion","Opposition","Kontroverse"],hint:"The noun from Latin 'coalitio' (growing together). Multiple parties governing together.",sSrc:"The government is almost always a coalition of two or three parties."},
{type:"teach",trg:"der Gesetzentwurf",src:"the bill, the draft law",pos:"noun",gender:"m",note:"'Gesetz' (law) + 'Entwurf' (draft). Before a law becomes\nlaw, it starts as an Entwurf. Long legislative road.",example:"A: Wer hat den Gesetzentwurf geschrieben?\nB: Das Ministerium hat den Gesetzentwurf erarbeitet.\nA: Wurde der Gesetzentwurf angenommen?\nB: Nein, der Gesetzentwurf wurde abgelehnt.",exampleSrc:"A: Who wrote the bill?\nB: The ministry drafted the bill.\nA: Was the bill accepted?\nB: No, the bill was rejected.",funFact:"'Gesetz' (law) + 'Entwurf' (draft/design). Before a Gesetz becomes law, it starts as an Entwurf. Three readings in the Bundestag, Bundesrat approval, presidential signature. Long road."},
{type:"teach",trg:"der Ausschuss",src:"the committee",pos:"noun",gender:"m",note:"From 'ausschliessen' (to exclude) in the sense of a selected group.\n25 standing committees in the Bundestag.",example:"A: Welcher Ausschuss ist zust\u00e4ndig?\nB: Der Ausschuss f\u00fcr Inneres.\nA: Was macht ein Ausschuss?\nB: Er pr\u00fcft Gesetze und h\u00f6rt Experten.",exampleSrc:"A: Which committee is responsible?\nB: The Committee for Internal Affairs.\nA: What does a committee do?\nB: It examines laws and hears experts.",funFact:"The real legislative work happens in Aussch\u00fcsse: they examine bills, hear experts, and write amendments. There are 25 standing committees in the Bundestag. The word comes from 'ausschliessen' (to exclude), meaning a selected group."},
{type:"teach",trg:"der Abgeordnete",src:"the member of parliament",pos:"noun",gender:"m",note:"From 'abordnen' (to delegate). Declines like an adjective:\nder Abgeordnete, ein Abgeordneter.",example:"A: Wer ist Ihr Abgeordneter?\nB: Der Abgeordnete f\u00fcr meinen Wahlkreis.\nA: Was macht ein Abgeordneter?\nB: Er vertritt die B\u00fcrger im Bundestag.",exampleSrc:"A: Who is your member of parliament?\nB: The member for my constituency.\nA: What does a member of parliament do?\nB: He represents the citizens in the Bundestag.",funFact:"Over 700 people hold this title in the current Bundestag. Like 'Angestellte,' it declines as an adjective: der Abgeordnete, die Abgeordnete, ein Abgeordneter. The root 'abordnen' means to delegate."},
{type:"teach",trg:"die Reform",src:"the reform",pos:"noun",gender:"f",note:"From Latin 'reformare' (to reshape). German political history\nis measured in reforms: Agenda 2010, Energiewende.",example:"A: Brauchen wir eine Reform?\nB: Ja, das System braucht eine Reform.\nA: Welche Reform ist am wichtigsten?\nB: Die Bildungsreform, sagen viele.",exampleSrc:"A: Do we need a reform?\nB: Yes, the system needs a reform.\nA: Which reform is most important?\nB: The education reform, many say.",funFact:"German political history is measured in reforms: Agenda 2010, Energiewende, Bildungsreform. Each one reshapes something fundamental. The Latin 'reformare' means exactly that: to reshape."},
{type:"teach",trg:"der Wahlkampf",src:"the election campaign",pos:"noun",gender:"m",note:"'Wahl' (election) + 'Kampf' (fight/battle). Literally\n'election battle.' Shorter than American campaigns.",example:"A: Wann beginnt der Wahlkampf?\nB: Der Wahlkampf startet drei Monate vor der Wahl.\nA: Ist der Wahlkampf teuer?\nB: Ja, aber weniger als in Amerika.",exampleSrc:"A: When does the election campaign begin?\nB: The campaign starts three months before the election.\nA: Is the campaign expensive?\nB: Yes, but less than in America.",funFact:"'Wahl' (election) + 'Kampf' (fight/battle). Literally 'election battle.' German Wahlkampf is shorter and less expensive than American campaigns. TV debates (Kanzlerduell) are the highlight."},
{type:"match",pairs:[{trg:"der Ausschuss",src:"the committee"},{trg:"der Abgeordnete",src:"the member of parliament"},{trg:"die Reform",src:"the reform"},{trg:"der Wahlkampf",src:"the election campaign"}]},
{type:"teach",trg:"das Grundgesetz",src:"the Basic Law (German constitution)",pos:"noun",gender:"n",note:"'Grund' (ground/basic) + 'Gesetz' (law). Written in 1949.\nDeliberately not called 'Constitution.'",example:"A: Was steht im Grundgesetz?\nB: Die Grundrechte aller B\u00fcrger.\nA: Kann man das Grundgesetz \u00e4ndern?\nB: Nur mit einer Zweidrittelmehrheit.",exampleSrc:"A: What is in the Basic Law?\nB: The fundamental rights of all citizens.\nA: Can the Basic Law be changed?\nB: Only with a two-thirds majority.",funFact:"'Grund' (ground/basic) + 'Gesetz' (law). Germany's constitution, written in 1949. Deliberately called 'Basic Law' not 'Constitution' because reunification was still hoped for. The name stuck."},
{type:"mc",q:"Das Grundgesetz wurde 1949 geschrieben. Warum wurde es nicht 'Verfassung' genannt?",opts:["Weil Deutschland keine Demokratie hatte","Weil es nur ein Entwurf war","Weil Frankreich dagegen war","Weil die Wiedervereinigung noch erhofft wurde"],ans:"Weil die Wiedervereinigung noch erhofft wurde",hint:"The name 'Basic Law' was deliberate: Germany was divided, and a permanent constitution was intended for a reunified nation."}
]},
{id:"deu_r29l2b",title:"Argumente und Gegenargumente (Teil 2)",icon:"\u2696\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Argumente und Gegenargumente (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"das Grundrecht",src:"the fundamental right",pos:"noun",gender:"n",note:"'Grund' (basic) + 'Recht' (right). Articles 1-19 of the\nGrundgesetz. They cannot be abolished. Ever.",example:"A: Was ist ein Grundrecht?\nB: Zum Beispiel die Meinungsfreiheit.\nA: Kann ein Grundrecht abgeschafft werden?\nB: Nein, Grundrechte sind unantastbar.",exampleSrc:"A: What is a fundamental right?\nB: For example, freedom of expression.\nA: Can a fundamental right be abolished?\nB: No, fundamental rights are inviolable.",funFact:"'Grund' (basic) + 'Recht' (right). Articles 1-19 of the Grundgesetz are Grundrechte: dignity, freedom, equality, religious freedom, press freedom. They cannot be abolished. Ever. That is the lesson of history."},
{type:"teach",trg:"die Kontroverse",src:"the controversy",pos:"noun",gender:"f",note:"From Latin 'controversia.' More structured than 'Streit.'\nA Kontroverse involves positions and public discourse.",example:"A: Die Kontroverse dauert schon Wochen.\nB: Ja, es gibt keine einfache L\u00f6sung.\nA: Ist die Kontroverse berechtigt?\nB: Ja, beide Seiten haben gute Argumente.",exampleSrc:"A: The controversy has lasted for weeks.\nB: Yes, there is no simple solution.\nA: Is the controversy justified?\nB: Yes, both sides have good arguments.",funFact:"Unlike a Streit (quarrel), a Kontroverse involves structured positions, arguments, and public discourse. Intellectual, not emotional. The Latin 'controversia' carries that same weight of formal disagreement."},
{type:"teach",trg:"die Ma\u00dfnahme",src:"the measure, the action taken",pos:"noun",gender:"f",note:"'Ma\u00df' (measure) + 'nahme' (taking). 'Ma\u00dfnahmen ergreifen'\n(to take measures). Always plural in political speech.",example:"A: Welche Ma\u00dfnahmen plant die Regierung?\nB: Neue Ma\u00dfnahmen gegen Arbeitslosigkeit.\nA: Sind die Ma\u00dfnahmen ausreichend?\nB: Nein, wir brauchen mehr Ma\u00dfnahmen.",exampleSrc:"A: What measures is the government planning?\nB: New measures against unemployment.\nA: Are the measures sufficient?\nB: No, we need more measures.",funFact:"'Ma\u00df' (measure) + 'nahme' (taking). 'Ma\u00dfnahmen ergreifen' (to take measures) is political language for doing something. Always plural in political speech: never just one measure, always a package."},
{type:"teach",trg:"das Bedenken",src:"the concern, the reservation",pos:"noun",gender:"n",note:"From 'bedenken' (to consider). 'Ich habe Bedenken' is the\ndiplomatic way to say 'I disagree.'",example:"A: Haben Sie Bedenken gegen den Vorschlag?\nB: Ja, ich habe ernste Bedenken.\nA: Welche Bedenken genau?\nB: Meine Bedenken betreffen die Kosten.",exampleSrc:"A: Do you have concerns about the proposal?\nB: Yes, I have serious concerns.\nA: What concerns exactly?\nB: My concerns relate to the costs.",funFact:"'Ich habe Bedenken' (I have concerns) is the diplomatic way to say 'I disagree.' Softer than Einwand, more serious than Zweifel. The verb 'bedenken' means to consider carefully before objecting."},
{type:"teach",trg:"die Forderung",src:"the demand",pos:"noun",gender:"f",note:"From 'fordern' (to demand). Stronger than Wunsch (wish)\nor Bitte (request). Parties announce Forderungen.",example:"A: Was ist die Forderung der Opposition?\nB: Ihre Forderung: niedrigere Steuern.\nA: Ist die Forderung realistisch?\nB: Das h\u00e4ngt vom Kompromiss ab.",exampleSrc:"A: What is the opposition's demand?\nB: Their demand: lower taxes.\nA: Is the demand realistic?\nB: That depends on the compromise.",funFact:"Political parties announce their Forderungen before coalition negotiations begin. Stronger than a Wunsch (wish) or Bitte (request), a Forderung carries real weight. Built on 'fordern' (to demand)."},
{type:"match",pairs:[{trg:"die Kontroverse",src:"the controversy"},{trg:"die Ma\u00dfnahme",src:"the measure, the action taken"},{trg:"das Bedenken",src:"the concern, the reservation"},{trg:"die Forderung",src:"the demand"}]},
{type:"teach",trg:"ablehnen",src:"to reject, to decline",pos:"verb",gender:null,note:"'Ab' (off) + 'lehnen' (to lean). Separable. You lean away\nfrom something. The formal 'no' in parliament.",example:"A: Hat die Fraktion den Entwurf abgelehnt?\nB: Ja, sie lehnte ihn einstimmig ab.\nA: Warum lehnen sie ihn ab?\nB: Weil er zu teuer ist.",exampleSrc:"A: Did the parliamentary group reject the bill?\nB: Yes, they rejected it unanimously.\nA: Why do they reject it?\nB: Because it is too expensive.",funFact:"'Ab' (off) + 'lehnen' (to lean). Separable. You lean away from something. The formal way to say no in parliament. 'Der Antrag wurde abgelehnt' (The motion was rejected)."},
{type:"teach",trg:"beschlie\u00dfen",src:"to decide, to pass (a law)",pos:"verb",gender:null,note:"'Be-' + 'schlie\u00dfen' (to close). To close a matter by deciding.\nStrong verb: beschloss, beschlossen. Not separable.",example:"A: Hat das Parlament das Gesetz beschlossen?\nB: Ja, es wurde gestern beschlossen.\nA: Wer hat den Beschluss gef\u00e4llt?\nB: Die Mehrheit hat beschlossen.",exampleSrc:"A: Did parliament pass the law?\nB: Yes, it was passed yesterday.\nA: Who made the decision?\nB: The majority decided.",funFact:"'Be-' + 'schlie\u00dfen' (to close). Literally to close a matter by deciding. Strong verb: beschlie\u00dfen, beschloss, beschlossen. Not separable. When parliament beschlie\u00dft, the debate is closed."},
{type:"teach",trg:"einwenden",src:"to object",pos:"verb",gender:null,note:"'Ein' (in) + 'wenden' (to turn). Separable. You turn IN with\nan objection. Formal and precise.",example:"A: Was wenden Sie dagegen ein?\nB: Ich wende ein, dass die Kosten zu hoch sind.\nA: Kann man nichts einwenden?\nB: Doch, Einw\u00e4nde sind immer willkommen.",exampleSrc:"A: What is your objection to it?\nB: I object that the costs are too high.\nA: Can one not object?\nB: Of course, objections are always welcome.",funFact:"'Ein' (in) + 'wenden' (to turn). Separable. You turn IN with an objection. Formal and precise. The polite cousin of 'widersprechen.' 'Dagegen ist einzuwenden, dass...' (The objection to that is that...)."},
{type:"teach",trg:"entgegnen",src:"to reply, to retort",pos:"verb",gender:null,note:"'Ent-' + 'gegnen' (from 'gegen,' against). Not separable.\nMore formal than 'antworten.' A substantive response.",example:"A: Was hat der Minister entgegnet?\nB: Er entgegnete: 'Das sehe ich anders.'\nA: War die Entgegnung \u00fcberzeugend?\nB: Ja, er entgegnete mit starken Fakten.",exampleSrc:"A: What did the minister reply?\nB: He replied: 'I see that differently.'\nA: Was the response convincing?\nB: Yes, he replied with strong facts.",funFact:"'Ent-' + 'gegnen' (from 'gegen,' against). Not separable. More formal than 'antworten.' Implies you are responding to a specific point with substance. 'Er entgegnete: Das sehe ich anders.'"},
{type:"fb",s:"Der {1} pr\u00fcft den Gesetzentwurf im Detail und h\u00f6rt Experten.",a:["Ausschuss"],opts:["Ausschuss","Bundestag","Wahlkampf","Grundgesetz"],hint:"The parliamentary committee that does the detailed legislative work. From 'ausschliessen' (a selected group).",sSrc:"The committee examines the bill in detail and hears experts."},
{type:"teach",trg:"verabschieden",src:"to pass (a law), to adopt",pos:"verb",gender:null,note:"'Ver-' + 'Abschied' (farewell). The law 'departs' from\ndraft status into reality. Not separable.",example:"A: Wurde das Gesetz verabschiedet?\nB: Ja, es wurde letzte Woche verabschiedet.\nA: Wie wird ein Gesetz verabschiedet?\nB: Durch Abstimmung im Bundestag.",exampleSrc:"A: Was the law passed?\nB: Yes, it was passed last week.\nA: How is a law passed?\nB: By vote in the Bundestag.",funFact:"'Ver-' + 'Abschied' (farewell). The law 'departs' from draft status into reality. Also: 'sich verabschieden' (to say goodbye). 'Das Gesetz wurde verabschiedet' (The law was passed)."},
{type:"tip",title:"Wie ein deutsches Gesetz entsteht",text:"A bill begins in a ministry or in the Bundestag.\n\n1. First reading: introduction in the plenary session\n2. Committee: detailed review, expert hearings, amendments\n3. Second reading: committee report\n4. Third reading: final vote\n5. Bundesrat: approval by the states\n6. Federal President: signature\n\nThen: 'Verk\u00fcndet im Bundesgesetzblatt.' Binding law.",deepDive:{title:"The legislative process",text:"Not every law needs Bundesrat approval. 'Zustimmungsgesetze' (consent laws) need it. 'Einspruchsgesetze' (objection laws) can override a Bundesrat veto with a Bundestag majority. The distinction matters because it determines how much power the L\u00e4nder have over federal legislation."}},
{type:"mc",q:"Bevor ein Gesetzentwurf Gesetz wird, wird er im Detail gepr\u00fcft von einem...",opts:["Koalition (B\u00fcndnis)","Ausschuss (Komitee)","Wahlkampf (Kampagne)","Fraktion (Parlamentsgruppe)"],ans:"Ausschuss (Komitee)",hint:"The body that hears experts, works out amendments, and does the actual legislative work."},
{type:"match",pairs:[{trg:"Abgeordnete",src:"member of parliament"},{trg:"Fraktion",src:"parliamentary group"},{trg:"Gesetzentwurf",src:"draft law/bill"},{trg:"Grundgesetz",src:"Basic Law/constitution"}]},
{type:"fb",s:"Das Parlament hat das neue Gesetz {1}.",a:["verabschiedet"],opts:["verabschiedet","abgelehnt","eingewendet","kritisiert"],hint:"The verb used when a legislative body officially approves and passes a law. It implies a formal send-off from the drafting stage.",sSrc:"Parliament passed the new law."},
{type:"mc",q:"'Ich habe Bedenken' ist diplomatischer als 'Ich lehne ab.' Warum?",opts:["Bedenken bedeutet dasselbe wie ablehnen und ist unhöflich","Bedenken ist weniger formell","Bedenken dr\u00fcckt Sorge aus, ohne direkte Ablehnung","Bedenken bedeutet Zustimmung"],ans:"Bedenken dr\u00fcckt Sorge aus, ohne direkte Ablehnung",hint:"This noun expresses thoughtful hesitation rather than outright refusal. It is diplomatic: you have considered and are worried, not simply opposed."},
{type:"mc",q:"Was bedeutet 'das Grundrecht'?",opts:["the fundamental right","the counterargument","the member of parliament","the coalition"],ans:"the fundamental right",hint:"Grund (foundation/basic) + Recht (legal entitlement). Guaranteed by the constitution."},
{type:"fb",s:"Wie sagt man 'the concern, the reservation' auf Deutsch? {1}",a:["das Bedenken"],opts:["das Bedenken","das Gegenargument","das Grundrecht","einwenden"],hint:"From the verb meaning 'to consider carefully'. Thoughtful hesitation, not outright refusal.",sSrc:"How do you say 'the concern, the reservation' in German?"},
{type:"mc",q:"Was bedeutet 'einwenden'?",opts:["to pass (a law), to adopt","to object","the parliamentary group","the committee"],ans:"to object",hint:"ein- (in) + wenden (to turn). To turn something in, to register a formal dissent."},
{type:"fb",s:"Wie sagt man 'to reply, to retort' auf Deutsch? {1}",a:["entgegnen"],opts:["entgegnen","das Gegenargument","das Grundrecht","der Abgeordnete"],hint:"From entgegen (against/toward). To speak back, often in disagreement.",sSrc:"How do you say 'to reply, to retort' in German?"},
{type:"mc",q:"Was bedeutet 'verabschieden'?",opts:["to pass (a law), to adopt","the election campaign","the bill, the draft law","the compromise"],ans:"to pass (a law), to adopt",hint:"ver- + Abschied (farewell). Parliament formally 'sends off' a bill into legislation."}
]},
{id:"deu_r29l3",title:"Einerseits... andererseits",icon:"\u2194\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Einerseits... andererseits",desc:"The panel discussion is in full swing. Panelists debate with two-part connectors. Learn these powerful bracket constructions of German argumentation.",goals:["Master two-part connectors (sowohl...als auch, weder...noch)","Structure balanced arguments in German","Understand word order with paired conjunctions"]},
{type:"teach",trg:"einerseits",src:"on the one hand",pos:"adv",gender:null,note:"'Einer' (one) + 'seits' (side). Always paired with\n'andererseits.' The opening bracket of balanced argumentation.",example:"A: Was denkst du \u00fcber die Reform?\nB: Einerseits ist sie n\u00f6tig.\nA: Und andererseits?\nB: Einerseits ja, andererseits zu schnell.",exampleSrc:"A: What do you think about the reform?\nB: On the one hand it is necessary.\nA: And on the other hand?\nB: On the one hand yes, on the other hand too fast.",funFact:"'Einer' (one) + 'seits' (side). Always paired with andererseits. In academic German, starting with 'einerseits' signals: I will present both sides before taking my position."},
{type:"teach",trg:"andererseits",src:"on the other hand",pos:"adv",gender:null,note:"'Anderer' (other) + 'seits' (side). The closing bracket.\nThe classic German fairness structure.",example:"A: Einerseits ist die Idee gut.\nB: Andererseits ist sie teuer.\nA: Einerseits...andererseits. Ein Dilemma.\nB: Genau. Andererseits gibt es immer Gegenargumente.",exampleSrc:"A: On the one hand the idea is good.\nB: On the other hand it is expensive.\nA: On the one hand...on the other. A dilemma.\nB: Exactly. On the other hand there are always counterarguments.",funFact:"'Anderer' (other) + 'seits' (side). The closing bracket. Together, einerseits...andererseits creates the classic German fairness structure: acknowledge both perspectives before taking your position."},
{type:"teach",trg:"jedoch",src:"however, yet",pos:"adv",gender:null,note:"From Middle High German 'iedoch.' Position: after the verb\nor as a conjunction. More formal than 'aber.'",example:"A: Der Plan klingt gut, jedoch gibt es Risiken.\nB: Welche Risiken jedoch?\nA: Die Kosten sind hoch, jedoch machbar.\nB: Jedoch m\u00fcssen wir vorsichtig sein.",exampleSrc:"A: The plan sounds good, however there are risks.\nB: What risks though?\nA: The costs are high, yet manageable.\nB: However, we must be careful.",funFact:"Think of 'jedoch' as the elevated 'aber.' It sits after the verb: 'Das ist richtig, jedoch sehe ich das anders.' Traced back to Middle High German 'iedoch,' it has always been the more formal 'but.'"},
{type:"mc",q:"Einerseits m\u00fcssen wir offen sein. Andererseits d\u00fcrfen wir unsere Werte nicht vergessen. Was schafft 'einerseits...andererseits'?",opts:["Eine logische Schlussfolgerung aus Beweisen","Eine ausgewogene Darstellung beider Seiten","Eine Bedingung ohne wenn-Konjunktion","Eine starke Konzession trotz Widerstand"],ans:"Eine ausgewogene Darstellung beider Seiten",hint:"One side... the other side. The classic German fairness structure for presenting two perspectives before deciding."},
{type:"teach",trg:"hingegen",src:"on the contrary, in contrast",pos:"adv",gender:null,note:"'Hin' (towards) + 'gegen' (against). Sharper contrast\nthan 'andererseits.' Position 1 or Mittelfeld.",example:"A: Die Regierung ist daf\u00fcr.\nB: Die Opposition hingegen ist dagegen.\nA: Und die B\u00fcrger?\nB: Sie hingegen sind gespalten.",exampleSrc:"A: The government is in favor.\nB: The opposition, in contrast, is against it.\nA: And the citizens?\nB: They, on the contrary, are divided.",funFact:"'Hin' (towards) + 'gegen' (against). 'Die Regierung ist daf\u00fcr, die Opposition hingegen dagegen.' Hingegen sits in position 1 or in the Mittelfeld. Sharper contrast than andererseits."},
{type:"teach",trg:"sowohl...als auch",src:"both...and",pos:"conj",gender:null,note:"'So' (so) + 'wohl' (well/indeed) + 'als auch' (as also).\nBoth elements get equal status. The connector of inclusion.",example:"A: Wer ist betroffen?\nB: Sowohl die Regierung als auch die Opposition.\nA: Sowohl Einheimische als auch Neuank\u00f6mmlinge?\nB: Ja, sowohl die einen als auch die anderen.",exampleSrc:"A: Who is affected?\nB: Both the government and the opposition.\nA: Both locals and newcomers?\nB: Yes, both the one group and the other.",funFact:"'So' (so) + 'wohl' (well/indeed) + 'als' (as) + 'auch' (also). Not just one, but BOTH. The connector of inclusion. Word order: both elements get equal grammatical status."},
{type:"teach",trg:"weder...noch",src:"neither...nor",pos:"conj",gender:null,note:"The connector of double negation. After 'weder,' the verb\ncan invert. After 'noch,' it must.",example:"A: Wer hat zugestimmt?\nB: Weder die Mehrheit noch die Minderheit.\nA: Weder die Regierung noch die Opposition?\nB: Genau. Weder noch. Niemand.",exampleSrc:"A: Who agreed?\nB: Neither the majority nor the minority.\nA: Neither the government nor the opposition?\nB: Exactly. Neither nor. Nobody.",funFact:"'Weder' (neither) + 'noch' (nor). The connector of double negation. 'Weder die Mehrheit noch die Minderheit war zufrieden.' After weder, the verb can invert. After noch, it must."},
{type:"teach",trg:"zwar...aber",src:"admittedly...but",pos:"conj",gender:null,note:"'Zwar' (indeed/admittedly) + 'aber' (but). Zwar concedes\na point, aber delivers the counterpoint. 'Yes, but.'",example:"A: Ist der Vorschlag gut?\nB: Er ist zwar gut, aber teuer.\nA: Zwar populaer, aber unrealistisch?\nB: Zwar nicht perfekt, aber ein Anfang.",exampleSrc:"A: Is the proposal good?\nB: It is admittedly good, but expensive.\nA: Admittedly popular but unrealistic?\nB: Admittedly not perfect, but a start.",funFact:"'Zwar' (indeed/admittedly) + 'aber' (but). 'Das Gesetz ist zwar popul\u00e4r, aber schwer umzusetzen.' Zwar concedes a point, aber delivers the counterpoint. The connector of 'yes, but.'"},
{type:"teach",trg:"je...desto",src:"the more...the more",pos:"conj",gender:null,note:"After 'je': comparative + verb at end. After 'desto':\ncomparative + inverted verb. Precise grammar brackets.",example:"A: Je l\u00e4nger die Debatte, desto klarer die Standpunkte.\nB: Je mehr man diskutiert, desto besser versteht man.\nA: Je kontroverser, desto interessanter?\nB: Genau. Je mehr Meinungen, desto reicher die Debatte.",exampleSrc:"A: The longer the debate, the clearer the viewpoints.\nB: The more you discuss, the better you understand.\nA: The more controversial, the more interesting?\nB: Exactly. The more opinions, the richer the debate.",funFact:"'Je' (ever/the) + 'desto' (the). After je: comparative + verb at end. After desto: comparative + inverted verb. Precise grammar brackets."},
{type:"fb",s:"Der Vorschlag ist {1} gut, aber teuer.",a:["zwar"],opts:["zwar","jedoch","ebenso","weder"],hint:"The first word of the concessive pair that means 'admittedly...but.' Concede a point, then deliver the counterpoint.",sSrc:"The proposal is admittedly good, but expensive."}
]},
{id:"deu_r29l3b",title:"Einerseits... andererseits (Teil 2)",icon:"\u2194\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Einerseits... andererseits (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"teils...teils",src:"partly...partly",pos:"adv",gender:null,note:"'Teils' (partly). When you cannot commit to one side.\nThe connector of ambivalence. Short, balanced, honest.",example:"A: Wie waren die Reaktionen?\nB: Teils positiv, teils negativ.\nA: Und die Presse?\nB: Teils begeistert, teils kritisch.",exampleSrc:"A: How were the reactions?\nB: Partly positive, partly negative.\nA: And the press?\nB: Partly enthusiastic, partly critical.",funFact:"'Teils' (partly). 'Die Reaktionen waren teils positiv, teils negativ.' When you cannot commit to one side. The connector of ambivalence. Short, balanced, honest."},
{type:"teach",trg:"nicht nur...sondern auch",src:"not only...but also",pos:"conj",gender:null,note:"The connector of addition with emphasis. Not just X.\nAlso Y. After 'sondern auch,' you deliver the surprise.",example:"A: Spricht er nur Deutsch?\nB: Nicht nur Deutsch, sondern auch T\u00fcrkisch.\nA: Nicht nur die Regierung handelt?\nB: Nicht nur die Regierung, sondern auch die B\u00fcrger.",exampleSrc:"A: Does he only speak German?\nB: Not only German, but also Turkish.\nA: Not only the government acts?\nB: Not only the government, but also the citizens.",funFact:"'Not only...but also.' 'Er spricht nicht nur Deutsch, sondern auch T\u00fcrkisch.' The connector of addition with emphasis. After sondern auch, you deliver the surprise element."},
{type:"teach",trg:"ebenso wie",src:"just as, equally as",pos:"conj",gender:null,note:"'Ebenso' (just as) + 'wie' (as). Both sides affected equally.\nFormal and precise. The connector of equality.",example:"A: Wen betrifft die Integration?\nB: Neuank\u00f6mmlinge ebenso wie Einheimische.\nA: Ebenso wie in anderen L\u00e4ndern?\nB: Ja, ebenso wie \u00fcberall sonst.",exampleSrc:"A: Who does integration affect?\nB: Newcomers just as much as locals.\nA: Just as in other countries?\nB: Yes, just as everywhere else.",funFact:"'Ebenso' (just as) + 'wie' (as). 'Integration betrifft Neuank\u00f6mmlinge ebenso wie Einheimische.' The connector of equality. Both sides affected equally. Formal and precise."},
{type:"teach",trg:"die Abstimmung",src:"the vote",pos:"noun",gender:"f",note:"'Ab' (off) + 'Stimmung' (tuning/mood). Literally: tuning\ntogether. 'Namentliche Abstimmung' = roll-call vote.",example:"A: Wann findet die Abstimmung statt?\nB: Die Abstimmung ist morgen.\nA: Wie funktioniert die Abstimmung?\nB: Per Handzeichen oder namentliche Abstimmung.",exampleSrc:"A: When does the vote take place?\nB: The vote is tomorrow.\nA: How does the vote work?\nB: By show of hands or roll-call vote.",funFact:"'Ab' (off) + 'Stimmung' (tuning/mood). Literally: tuning together, reaching harmony. 'Namentliche Abstimmung' (roll-call vote) is when every Abgeordnete's vote is recorded publicly."},
{type:"teach",trg:"die Mehrheit",src:"the majority",pos:"noun",gender:"f",note:"'Mehr' (more) + '-heit' (state of). 'Einfache Mehrheit' =\n50%+1. 'Zweidrittelmehrheit' to change the Grundgesetz.",example:"A: Hat die Koalition die Mehrheit?\nB: Ja, eine knappe Mehrheit.\nA: Reicht eine einfache Mehrheit?\nB: F\u00fcr dieses Gesetz brauchen wir eine Zweidrittelmehrheit.",exampleSrc:"A: Does the coalition have the majority?\nB: Yes, a narrow majority.\nA: Is a simple majority enough?\nB: For this law we need a two-thirds majority.",funFact:"'Mehr' (more) + '-heit' (state of). 'Einfache Mehrheit' (simple majority) = 50%+1. 'Zweidrittelmehrheit' (two-thirds majority) needed to change the Grundgesetz. Numbers that shape law."},
{type:"match",pairs:[{trg:"nicht nur...sondern auch",src:"not only...but also"},{trg:"ebenso wie",src:"just as, equally as"},{trg:"die Abstimmung",src:"the vote"},{trg:"die Mehrheit",src:"the majority"}]},
{type:"teach",trg:"die Minderheit",src:"the minority",pos:"noun",gender:"f",note:"'Minder' (less) + '-heit.' 'Minderheitenschutz' (minority\nprotection) is a core principle of German democracy.",example:"A: Hat die Minderheit Rechte?\nB: Ja, Minderheitenschutz ist ein Grundprinzip.\nA: Kann die Minderheit \u00fcberstimmt werden?\nB: Ja, aber ihre Rechte bleiben gesch\u00fctzt.",exampleSrc:"A: Does the minority have rights?\nB: Yes, minority protection is a fundamental principle.\nA: Can the minority be outvoted?\nB: Yes, but their rights remain protected.",funFact:"'Minder' (less) + '-heit.' 'Minderheitenschutz' (minority protection) is a core principle of German democracy. The Grundgesetz protects minorities from the 'Tyrannei der Mehrheit.'"},
{type:"teach",trg:"der Kanzler",src:"the chancellor (male)",pos:"noun",gender:"m",note:"From Latin 'cancellarius.' The head of government.\nHas 'Richtlinienkompetenz': power to set policy direction.",example:"A: Wer ist der Kanzler?\nB: Der Kanzler f\u00fchrt die Regierung.\nA: Was entscheidet der Kanzler?\nB: Der Kanzler bestimmt die Richtlinien der Politik.",exampleSrc:"A: Who is the chancellor?\nB: The chancellor leads the government.\nA: What does the chancellor decide?\nB: The chancellor determines the guidelines of policy.",funFact:"The Kanzler is not the head of state (that is the Bundespr\u00e4sident), but holds 'Richtlinienkompetenz': the power to set government policy direction. The Latin 'cancellarius' originally meant a secretary behind a screen."},
{type:"mc",q:"Die Debatte war sowohl informativ als auch unterhaltsam. Was dr\u00fcckt 'sowohl...als auch' aus?",opts:["Nur eine der beiden Eigenschaften trifft zu","Beide Eigenschaften treffen gleichzeitig zu","Keine der beiden Eigenschaften stimmt","Die eine Eigenschaft schliesst die andere aus"],ans:"Beide Eigenschaften treffen gleichzeitig zu",hint:"The paired connector of inclusion. Both elements receive equal weight. Not one or the other, but BOTH."},
{type:"teach",trg:"die Kanzlerin",src:"the chancellor (female)",pos:"noun",gender:"f",note:"Kanzler + '-in.' Used prominently from 2005 to 2021.\n'Frau Bundeskanzlerin' was the official address.",example:"A: Wer war die erste Kanzlerin?\nB: Angela Merkel war die erste Kanzlerin.\nA: Wie lange war sie Kanzlerin?\nB: 16 Jahre lang war sie Bundeskanzlerin.",exampleSrc:"A: Who was the first female chancellor?\nB: Angela Merkel was the first female chancellor.\nA: How long was she chancellor?\nB: She was chancellor for 16 years.",funFact:"Kanzler + '-in.' Used prominently from 2005 to 2021. 'Frau Bundeskanzlerin' was the official address. The title normalized having women in the highest office."},
{type:"teach",trg:"die Verfassung",src:"the constitution",pos:"noun",gender:"f",note:"From 'verfassen' (to compose/author). Germany's Grundgesetz\nfunctions as a Verfassung but technically is not called one.",example:"A: Hat Deutschland eine Verfassung?\nB: Ja, das Grundgesetz ist die Verfassung.\nA: Kann man die Verfassung \u00e4ndern?\nB: Nur mit einer Zweidrittelmehrheit.",exampleSrc:"A: Does Germany have a constitution?\nB: Yes, the Basic Law is the constitution.\nA: Can the constitution be changed?\nB: Only with a two-thirds majority.",funFact:"Germany's Grundgesetz functions as a Verfassung but technically is not called one, a deliberate choice when the country was still divided. Literally 'something composed,' from 'verfassen' (to compose/author)."},
{type:"teach",trg:"der Widerstand",src:"resistance",pos:"noun",gender:"m",note:"'Wider' (against) + 'Stand' (standing). In German history,\n'der Widerstand' often means resistance against the Nazis.",example:"A: Gibt es Widerstand gegen das Gesetz?\nB: Ja, gro\u00dfer Widerstand aus der Bev\u00f6lkerung.\nA: Wie zeigt sich der Widerstand?\nB: Durch Demonstrationen und Petitionen.",exampleSrc:"A: Is there resistance against the law?\nB: Yes, strong resistance from the population.\nA: How is the resistance expressed?\nB: Through demonstrations and petitions.",funFact:"'Wider' (against) + 'Stand' (standing). 'Auf Widerstand sto\u00dfen' (to meet resistance). In German history, 'der Widerstand' often refers to resistance against the Nazi regime. A word with heavy moral weight."},
{type:"teach",trg:"pl\u00e4dieren",src:"to plead, to advocate",pos:"verb",gender:null,note:"From French 'plaider' (to plead). Originally a legal term.\nNow used broadly for strong advocacy.",example:"A: Wof\u00fcr pl\u00e4dieren Sie?\nB: Ich pl\u00e4diere f\u00fcr mehr Dialog.\nA: Pl\u00e4diert die Opposition f\u00fcr eine Reform?\nB: Ja, sie pl\u00e4diert f\u00fcr grundlegende \u00c4nderungen.",exampleSrc:"A: What do you advocate for?\nB: I advocate for more dialogue.\nA: Does the opposition advocate for a reform?\nB: Yes, they advocate for fundamental changes.",funFact:"Originally a courtroom word borrowed from French 'plaider' (to plead), where a Pl\u00e4doyer is a closing argument. Now it means any strong advocacy: 'Ich pl\u00e4diere f\u00fcr mehr Dialog' (I advocate for more dialogue)."},
{type:"teach",trg:"vertreten",src:"to represent",pos:"verb",gender:null,note:"'Ver-' + 'treten' (to step). You step into someone's place.\nStrong verb: vertreten, vertrat, vertreten.",example:"A: Wen vertreten Sie?\nB: Ich vertrete die B\u00fcrger meines Wahlkreises.\nA: Vertreten Sie diesen Standpunkt?\nB: Ja, ich vertrete ihn mit \u00dcberzeugung.",exampleSrc:"A: Who do you represent?\nB: I represent the citizens of my constituency.\nA: Do you hold this viewpoint?\nB: Yes, I represent it with conviction.",funFact:"'Ver-' + 'treten' (to step). You step into someone's place. Strong verb: vertreten, vertrat, vertreten. 'Ich vertrete den Standpunkt, dass...' (I hold the position that...)."},
{type:"verb_table",title:"Zweiteilige Konnektoren: Wortstellungsmuster",groups:[{label:"Gepaarte Konnektoren",rows:[{pronoun:"sowohl...als auch",form:"Sowohl A als auch B + Verb",src:"both A and B"},{pronoun:"weder...noch",form:"Weder A noch verb B",src:"neither A nor B"},{pronoun:"nicht nur...sondern auch",form:"Nicht nur A, sondern auch B",src:"not only A but also B"},{pronoun:"einerseits...andererseits",form:"Einerseits..., andererseits...",src:"on one hand... on the other"},{pronoun:"zwar...aber",form:"Zwar A, aber B",src:"admittedly... but"},{pronoun:"je...desto",form:"Je + Komp. + V-Ende, desto + Komp. + V2",src:"the more... the more"},{pronoun:"teils...teils",form:"Teils A, teils B",src:"partly... partly"}]}]},
{type:"tip",title:"Zweiteilige Konnektoren: Klammerkonstruktionen",text:"Two-part connectors frame your argument like brackets around the content.\n\nInclusion: sowohl...als auch (both)\nExclusion: weder...noch (neither)\nConcession: zwar...aber (yes, but...)\nProportion: je...desto (proportional comparison)\nAddition: nicht nur...sondern auch (addition with emphasis)\n\nKey rule for je...desto: after 'je,' the verb goes to the end.\nAfter 'desto,' the verb comes in position 2 (inversion).\nThese connectors are B2 tools for academic and professional discourse.",deepDive:{title:"Word order details",text:"Sowohl...als auch: both elements get equal grammatical weight. 'Sowohl die Regierung als auch die Opposition hat/haben zugestimmt.' Singular or plural verb is debated, but plural is more common.\n\nWeder...noch: double negation. 'Weder die Mehrheit noch die Minderheit war zufrieden.' Verb usually singular if both nouns are singular.\n\nJe...desto: 'Je l\u00e4nger die Debatte dauert, desto klarer werden die Argumente.' The je-clause is a subordinate clause (verb at end). The desto-clause has verb-second (inversion)."}},
{type:"drag_fill",s:"{1} die Mehrheit ist daf\u00fcr, {2} hat die Minderheit berechtigte Bedenken.",blanks:{"1":"Zwar","2":"aber"},pool:["Zwar","aber","Weder","noch","Sowohl","als"],hint:"Concede a point, then deliver the counterpoint. The pattern: acknowledge, then push back."},
{type:"mc",q:"Was bedeutet 'teils...teils'?",opts:["the minority","however, yet","on the contrary, in contrast","partly...partly"],ans:"partly...partly",hint:"From Teil (part). A paired conjunction: one part this, one part that."},
{type:"fb",s:"Wann findet {1} statt?",a:["die Abstimmung"],opts:["die Kanzlerin","andererseits","hingegen","die Abstimmung"],hint:"From abstimmen (to vote). The formal process of casting votes in parliament.",sSrc:"When does the vote take place?"},
{type:"mc",q:"Was bedeutet 'die Verfassung'?",opts:["both...and","the chancellor (female)","the constitution","the chancellor (male)"],ans:"the constitution",hint:"From verfassen (to compose/author). Germany's is called the Grundgesetz."},
{type:"fb",s:"Wie zeigt sich {1}?",a:["der Widerstand"],opts:["der Widerstand","sowohl...als auch","nicht nur...sondern auch","hingegen"],hint:"Compounded from 'against' + 'position'. Holding firm in opposition to something.",sSrc:"How is the resistance expressed?"},
{type:"mc",q:"Was bedeutet 'vertreten'?",opts:["resistance","on the one hand","the chancellor (male)","to represent"],ans:"to represent",hint:"ver- + treten (to step). To step in for someone. A Vertreter stands in for another."},
{type:"mc",q:"Der Anwalt will für strengere Gesetze...?",opts:["plädieren","vertreten","forcieren","zugestehen"],ans:"plädieren",hint:"To advocate or plead for something. Used in legal and debate contexts when arguing for a position."}
]},
{id:"deu_r29l4",title:"Obgleich und Wenngleich",icon:"\uD83D\uDD04",xp:15,board:true,steps:[
{type:"intro",title:"Obgleich und Wenngleich",desc:"Concessive clauses at B2 level. Learn the elevated variants of 'obwohl' and build the logical framework of formal argumentation.",goals:["Master concessive clauses: obgleich, wenngleich, wenn auch, selbst wenn","Distinguish between obwohl (B1) and its elevated variants","Build the logical framework of formal argumentation"]},
{type:"teach",trg:"obgleich",src:"although (literary)",pos:"conj",gender:null,note:"'Ob' (whether/if) + 'gleich' (equal/even). The elevated\nsibling of 'obwohl.' Subordinating: verb to the end.",example:"A: Obgleich die Debatte hitzig war, blieb der Ton respektvoll.\nB: Das stimmt. Obgleich alle verschiedener Meinung waren.\nA: Obgleich ich nervoes war, habe ich gesprochen.\nB: Gut gemacht, obgleich es schwer war.",exampleSrc:"A: Although the debate was heated, the tone remained respectful.\nB: That is true. Although everyone had different opinions.\nA: Although I was nervous, I spoke.\nB: Well done, although it was difficult.",funFact:"'Ob' (whether/if) + 'gleich' (equal/even). The elevated sibling of 'obwohl.' Subordinating conjunction: verb goes to the end. Used in written German, speeches, and academic texts."},
{type:"teach",trg:"wenngleich",src:"even though, albeit",pos:"conj",gender:null,note:"'Wenn' (when/if) + 'gleich' (equal/even). Slightly more formal\nthan 'obgleich.' The 'even if/even though' nuance.",example:"A: Wenngleich ich Ihre Meinung respektiere, teile ich sie nicht.\nB: Das ist fair. Wenngleich wir unterschiedlicher Meinung sind.\nA: Wenngleich es Widerstand gibt, m\u00fcssen wir handeln.\nB: Ja, wenngleich der Weg schwer ist.",exampleSrc:"A: Even though I respect your opinion, I do not share it.\nB: That is fair. Even though we disagree.\nA: Even though there is resistance, we must act.\nB: Yes, even though the path is difficult.",funFact:"'Wenn' (when/if) + 'gleich' (equal/even). Slightly more formal than obgleich. The 'even if/even though' nuance. 'Wenngleich ich Ihre Meinung respektiere, teile ich sie nicht.'"},
{type:"mc",q:"'Wenngleich ich Ihre Meinung respektiere, teile ich sie nicht.' Was ist 'wenngleich'?",opts:["Ein Vergleichsmarker f\u00fcr Gleichheit und \u00c4hnlichkeit","Eine Konjunktion f\u00fcr Ergebnis und direkte Folge","Ein Diskursmarker f\u00fcr formelle Zusammenfassung","Ein konzessives Bindewort: obwohl in gehobener Sprache"],ans:"Ein konzessives Bindewort: obwohl in gehobener Sprache",hint:"Wenn (when/if) + gleich (equal/even). A subordinating conjunction that concedes a point. The literary, elevated version of a common concessive conjunction."},
{type:"teach",trg:"wenn auch",src:"even if, although",pos:"conj",gender:null,note:"'Wenn' (if) + 'auch' (also/even). Can start the clause\nor appear mid-sentence. Less literary than obgleich.",example:"A: Wenn auch nicht alle zustimmen, ist der Beschluss g\u00fcltig.\nB: Ja, wenn auch die Minderheit dagegen war.\nA: Wenn auch sp\u00e4t, kam die Reform.\nB: Besser sp\u00e4t als nie, wenn auch knapp.",exampleSrc:"A: Even if not all agree, the resolution is valid.\nB: Yes, even though the minority was against it.\nA: Even if late, the reform came.\nB: Better late than never, even if barely.",funFact:"'Wenn' (if) + 'auch' (also/even). Can start the clause or appear mid-sentence. Less literary than obgleich, more flexible. 'Wenn auch nicht alle zustimmen, ist der Beschluss g\u00fcltig.'"},
{type:"teach",trg:"selbst wenn",src:"even if (strongest)",pos:"conj",gender:null,note:"'Selbst' (self/even) + 'wenn' (if). The strongest concessive:\neven in the worst case, the conclusion holds.",example:"A: Selbst wenn die Opposition dagegen stimmt, hat die Koalition die Mehrheit.\nB: Selbst wenn alle dagegen sind?\nA: Selbst wenn es Widerstand gibt, m\u00fcssen wir weitermachen.\nB: Ja, selbst wenn es schwer wird.",exampleSrc:"A: Even if the opposition votes against it, the coalition has the majority.\nB: Even if everyone is against it?\nA: Even if there is resistance, we must continue.\nB: Yes, even if it gets difficult.",funFact:"'Selbst' (self/even) + 'wenn' (if). The strongest concessive: even in the worst case, the conclusion holds. 'Selbst wenn die Opposition dagegen stimmt, hat die Koalition die Mehrheit.'"},
{type:"teach",trg:"trotz alledem",src:"despite all that, nevertheless",pos:"adv",gender:null,note:"'Trotz' (despite) + 'all' + 'dem' (that). A sentence-level\nconnector, not a conjunction. Emphatic.",example:"A: Die Lage ist schwierig.\nB: Trotz alledem glaube ich an den Dialog.\nA: Trotz alledem optimistisch?\nB: Ja, trotz alledem. Immer.",exampleSrc:"A: The situation is difficult.\nB: Despite all that, I believe in dialogue.\nA: Optimistic despite all that?\nB: Yes, despite all that. Always.",funFact:"'Trotz' (despite) + 'all' + 'dem' (that). A sentence-level connector, not a conjunction. I acknowledge everything you said. AND YET. Emphatic and defiant."},
{type:"fb",s:"{1} wir Fortschritte gemacht haben, reichen sie nicht.",a:["Obgleich"],opts:["Obgleich","Sodass","Infolgedessen","Somit"],hint:"The literary subordinating conjunction meaning 'although.' The elevated sibling of 'obwohl.' Sends the verb to the end.",sSrc:"Although we have made progress, it is not enough."},
{type:"teach",trg:"nichtsdestotrotz",src:"nevertheless, nonetheless",pos:"adv",gender:null,note:"'Nichts' + 'desto' + 'trotz.' A magnificent German word:\n'nothing-the-less-defiance.' Formal and powerful.",example:"A: Der Vorschlag ist umstritten.\nB: Nichtsdestotrotz sollten wir ihn pr\u00fcfen.\nA: Die Kritik ist berechtigt, nichtsdestotrotz...\nB: Nichtsdestotrotz m\u00fcssen wir handeln.",exampleSrc:"A: The proposal is contested.\nB: Nevertheless we should examine it.\nA: The criticism is justified, nevertheless...\nB: Nevertheless we must act.",funFact:"'Nichts' (nothing) + 'desto' (the) + 'trotz' (defiance). A magnificent German word: 'nothing-the-less-defiance.' Formal, powerful, and uniquely German in its construction."},
{type:"teach",trg:"nichtsdestoweniger",src:"nonetheless, nevertheless",pos:"adv",gender:null,note:"'Nichts' + 'desto' + 'weniger' (less). The slightly more formal\ntwin of nichtsdestotrotz. Academic register.",example:"A: Die Bedenken sind berechtigt.\nB: Nichtsdestoweniger m\u00fcssen wir handeln.\nA: Das Risiko ist hoch, nichtsdestoweniger...\nB: Nichtsdestoweniger bleibt die Reform n\u00f6tig.",exampleSrc:"A: The concerns are justified.\nB: Nonetheless we must act.\nA: The risk is high, nonetheless...\nB: Nonetheless the reform remains necessary.",funFact:"'Nichts' (nothing) + 'desto' (the) + 'weniger' (less). The slightly more formal twin of nichtsdestotrotz. Academic register. 'Die Bedenken sind berechtigt, nichtsdestoweniger m\u00fcssen wir handeln.'"},
{type:"teach",trg:"sodass",src:"so that, with the result that",pos:"conj",gender:null,note:"'So' (so) + 'dass' (that). Result clause: the first part\ncauses the second. Subordinating: verb at the end.",example:"A: Die Debatte war konstruktiv, sodass ein Kompromiss m\u00f6glich wurde.\nB: Alle haben zugestimmt, sodass das Gesetz verabschiedet wurde.\nA: Er sprach klar, sodass alle ihn verstanden.\nB: Gut formuliert, sodass keine Fragen blieben.",exampleSrc:"A: The debate was constructive, so that a compromise became possible.\nB: Everyone agreed, so that the law was passed.\nA: He spoke clearly, so that everyone understood him.\nB: Well formulated, so that no questions remained.",funFact:"'So' (so) + 'dass' (that). Result clause: the first part causes the second. Subordinating: verb at the end after sodass. 'Die Debatte war konstruktiv, sodass ein Kompromiss m\u00f6glich wurde.'"},
{type:"teach",trg:"infolgedessen",src:"consequently, as a result",pos:"adv",gender:null,note:"'Infolge' (as a consequence of) + 'dessen' (that).\nFormal connective adverb. Written and academic register.",example:"A: Die Abstimmung scheiterte.\nB: Infolgedessen wurde der Entwurf \u00fcberarbeitet.\nA: Die Kosten stiegen, infolgedessen...\nB: Infolgedessen musste gespart werden.",exampleSrc:"A: The vote failed.\nB: Consequently the draft was revised.\nA: The costs rose, as a result...\nB: Consequently savings had to be made.",funFact:"'Infolge' (as a consequence of) + 'dessen' (that). Formal connective adverb. Position 1 or Mittelfeld. Written and academic register."},
{type:"teach",trg:"demzufolge",src:"consequently, accordingly",pos:"adv",gender:null,note:"'Dem' (that) + 'zufolge' (according to). Even more formal\nthan 'infolgedessen.' Legal and academic standard.",example:"A: Die Studie zeigt klare Ergebnisse.\nB: Demzufolge muss die Regierung reagieren.\nA: Demzufolge war die Reform n\u00f6tig?\nB: Ja, demzufolge gab es keine Alternative.",exampleSrc:"A: The study shows clear results.\nB: Accordingly the government must respond.\nA: Consequently the reform was necessary?\nB: Yes, accordingly there was no alternative.",funFact:"'Dem' (that) + 'zufolge' (according to). Even more formal than infolgedessen. The conclusion drawn from evidence. Legal and academic standard."},
{type:"match",pairs:[{trg:"nichtsdestoweniger",src:"nonetheless, nevertheless"},{trg:"sodass",src:"so that, with the result that"},{trg:"infolgedessen",src:"consequently, as a result"},{trg:"demzufolge",src:"consequently, accordingly"}]},
{type:"teach",trg:"somit",src:"thus, therefore",pos:"adv",gender:null,note:"'So' (so) + 'mit' (with). Short, conclusive, formal.\nThe period at the end of a logical chain.",example:"A: Alle Argumente wurden geh\u00f6rt.\nB: Somit ist die Frage beantwortet.\nA: Die Mehrheit hat zugestimmt, somit...\nB: Somit ist das Gesetz beschlossen.",exampleSrc:"A: All arguments have been heard.\nB: Thus the question is answered.\nA: The majority agreed, thus...\nB: Thus the law is decided.",funFact:"'So' (so) + 'mit' (with). Short, conclusive, formal. The period at the end of a logical chain. Shorter than infolgedessen but equally authoritative. 'Somit ist die Frage beantwortet.'"},
{type:"teach",trg:"die Pr\u00e4misse",src:"the premise",pos:"noun",gender:"f",note:"From Latin 'praemissa' (sent before). The starting assumption.\nIf the premise is wrong, the conclusion falls.",example:"A: Von welcher Pr\u00e4misse gehen Sie aus?\nB: Meine Pr\u00e4misse ist, dass Dialog hilft.\nA: Ist die Pr\u00e4misse richtig?\nB: Wenn die Pr\u00e4misse falsch ist, f\u00e4llt alles.",exampleSrc:"A: What premise are you starting from?\nB: My premise is that dialogue helps.\nA: Is the premise correct?\nB: If the premise is wrong, everything falls apart.",funFact:"If the Pr\u00e4misse is wrong, the entire argument collapses. 'Von welcher Pr\u00e4misse gehen Sie aus?' (What premise are you starting from?) is a powerful debate opener. Latin 'praemissa' means 'sent before,' the starting assumption."},
{type:"mc",q:"Die Debatte war konstruktiv, sodass ein Kompromiss m\u00f6glich wurde. Was dr\u00fcckt 'sodass' aus?",opts:["Einen klaren Kontrast zwischen zwei Standpunkten","Ein Ergebnis, das aus der ersten Handlung folgt","Eine Konzession trotz starken Widerstands","Eine klare Bedingung ganz ohne wenn"],ans:"Ein Ergebnis, das aus der ersten Handlung folgt",hint:"A conjunction expressing consequence. The first event led to the second happening."}
]},
{id:"deu_r29l4b",title:"Obgleich und Wenngleich (Teil 2)",icon:"\uD83D\uDD04",xp:15,board:true,steps:[
{type:"intro",title:"Obgleich und Wenngleich (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"die Schlussfolgerung",src:"the conclusion, the inference",pos:"noun",gender:"f",note:"'Schluss' (conclusion) + 'Folgerung' (inference). The compound\nitself tells the logic: closing + following from evidence.",example:"A: Was ist Ihre Schlussfolgerung?\nB: Meine Schlussfolgerung ist klar: wir brauchen Dialog.\nA: Ist die Schlussfolgerung logisch?\nB: Die logische Schlussfolgerung ergibt sich aus den Daten.",exampleSrc:"A: What is your conclusion?\nB: My conclusion is clear: we need dialogue.\nA: Is the conclusion logical?\nB: The logical conclusion follows from the data.",funFact:"'Schluss' (conclusion) + 'Folgerung' (inference). The compound itself tells the logic: closing + following from evidence. 'Die logische Schlussfolgerung ist...'"},
{type:"teach",trg:"die Stellungnahme",src:"the statement, the position paper",pos:"noun",gender:"f",note:"'Stellung' (position) + 'Nahme' (taking). You take a\nposition and make it public.",example:"A: Gibt es eine offizielle Stellungnahme?\nB: Ja, die Stellungnahme wurde ver\u00f6ffentlicht.\nA: Was sagt die Stellungnahme?\nB: Die Stellungnahme fordert mehr Dialog.",exampleSrc:"A: Is there an official statement?\nB: Yes, the statement was published.\nA: What does the statement say?\nB: The statement demands more dialogue.",funFact:"'Stellung' (position) + 'Nahme' (taking). 'Eine offizielle Stellungnahme abgeben' (to issue an official statement). You take a position and make it public."},
{type:"teach",trg:"die \u00dcberzeugung",src:"the conviction, the belief",pos:"noun",gender:"f",note:"From '\u00fcberzeugen' (to convince). Stronger than 'Meinung'\n(opinion). Something you cannot easily give up.",example:"A: Was ist Ihre \u00dcberzeugung?\nB: Meiner festen \u00dcberzeugung nach brauchen wir Reformen.\nA: \u00c4ndern Sie Ihre \u00dcberzeugung?\nB: Nein, das ist eine tiefe \u00dcberzeugung.",exampleSrc:"A: What is your conviction?\nB: In my firm conviction we need reforms.\nA: Will you change your conviction?\nB: No, that is a deep conviction.",funFact:"'Meiner festen \u00dcberzeugung nach...' (In my firm conviction...) is how you signal deep belief. Stronger than a Meinung (opinion), a conviction is something you cannot easily give up. Built on '\u00fcberzeugen' (to convince)."},
{type:"teach",trg:"die Kompromissbereitschaft",src:"willingness to compromise",pos:"noun",gender:"f",note:"'Kompromiss' + 'Bereitschaft' (readiness). A word that could\nonly exist in German politics. It is a political virtue.",example:"A: Zeigt die Regierung Kompromissbereitschaft?\nB: Ja, die Kompromissbereitschaft ist da.\nA: Ohne Kompromissbereitschaft...\nB: Ohne Kompromissbereitschaft scheitert jede Koalition.",exampleSrc:"A: Does the government show willingness to compromise?\nB: Yes, the willingness to compromise is there.\nA: Without willingness to compromise...\nB: Without willingness to compromise every coalition fails.",funFact:"'Kompromiss' + 'Bereitschaft' (readiness). A word that could only exist in German politics. 'Ohne Kompromissbereitschaft scheitert jede Koalition.' It is a political virtue."},
{type:"teach",trg:"begr\u00fcnden",src:"to justify, to give reasons for",pos:"verb",gender:null,note:"'Be-' + 'gr\u00fcnden' (to found/establish). Literally: to build a\nfoundation under your argument. Not separable.",example:"A: K\u00f6nnen Sie Ihren Standpunkt begr\u00fcnden?\nB: Ja, ich begr\u00fcnde ihn mit Fakten.\nA: Wie begr\u00fcnden Sie das?\nB: Ich begr\u00fcnde es mit drei Argumenten.",exampleSrc:"A: Can you justify your position?\nB: Yes, I justify it with facts.\nA: How do you justify that?\nB: I justify it with three arguments.",funFact:"'Be-' + 'gr\u00fcnden' (to found/establish). Literally: to establish a foundation under your argument. 'K\u00f6nnen Sie Ihren Standpunkt begr\u00fcnden?' (Can you justify your position?). Not separable."},
{type:"match",pairs:[{trg:"die Stellungnahme",src:"the statement, the position paper"},{trg:"die \u00dcberzeugung",src:"the conviction, the belief"},{trg:"die Kompromissbereitschaft",src:"willingness to compromise"},{trg:"begr\u00fcnden",src:"to justify, to give reasons for"}]},
{type:"teach",trg:"widerlegen",src:"to refute",pos:"verb",gender:null,note:"'Wider' (against) + 'legen' (to lay). You lay something\nagainst the claim and it falls. The ultimate debate move.",example:"A: Kann man das Argument widerlegen?\nB: Ja, es l\u00e4sst sich leicht widerlegen.\nA: Wie widerlegt man eine These?\nB: Indem man Gegenbeweise vorlegt.",exampleSrc:"A: Can the argument be refuted?\nB: Yes, it can be easily refuted.\nA: How does one refute a thesis?\nB: By presenting counter-evidence.",funFact:"'Wider' (against) + 'legen' (to lay). You lay something against the claim and it falls. The ultimate debate move: not disagreeing, but proving wrong. 'Das Argument l\u00e4sst sich leicht widerlegen.'"},
{type:"teach",trg:"abw\u00e4gen",src:"to weigh up, to consider carefully",pos:"verb",gender:null,note:"'Ab' (off) + 'w\u00e4gen' (to weigh). The image of scales:\nplacing arguments on each side. Separable.",example:"A: Haben Sie die Vor- und Nachteile abgew\u00e4gt?\nB: Ja, wir haben alles sorgf\u00e4ltig abgew\u00e4gt.\nA: Was \u00fcberwiegt, wenn man abw\u00e4gt?\nB: Die Vorteile \u00fcberwiegen, nachdem wir abgew\u00e4gt haben.",exampleSrc:"A: Have you weighed the pros and cons?\nB: Yes, we weighed everything carefully.\nA: What prevails when you weigh it up?\nB: The advantages prevail, after we weighed it up.",funFact:"'Ab' (off) + 'w\u00e4gen' (to weigh). 'Wir m\u00fcssen die Vor- und Nachteile abw\u00e4gen' (We must weigh the pros and cons). The image of scales: placing arguments on each side. Separable."},
{type:"fb",s:"Kann man das Argument {1}? Ja, indem man Gegenbeweise vorlegt.",a:["widerlegen"],opts:["widerlegen","begr\u00fcnden","abw\u00e4gen","einr\u00e4umen"],hint:"The verb from wider (against) + legen (to lay). The ultimate debate move: not disagreeing, but proving wrong.",sSrc:"Can the argument be refuted? Yes, by presenting counter-evidence."},
{type:"teach",trg:"einr\u00e4umen",src:"to concede, to admit",pos:"verb",gender:null,note:"'Ein' (in) + 'r\u00e4umen' (to clear/make room). Separable.\nYou clear room for the other's argument inside your own.",example:"A: R\u00e4umen Sie ein, dass er recht hat?\nB: Ich r\u00e4ume ein, dass er einen Punkt hat.\nA: Das ist fair. Sie r\u00e4umen Fehler ein.\nB: Ja, man muss Fehler einr\u00e4umen k\u00f6nnen.",exampleSrc:"A: Do you concede that he is right?\nB: I concede that he has a point.\nA: That is fair. You concede mistakes.\nB: Yes, one must be able to concede mistakes.",funFact:"'Ein' (in) + 'r\u00e4umen' (to clear/make room). Separable. You clear room for the other person's argument inside your own position. 'Ich r\u00e4ume ein, dass Sie einen Punkt haben.'"},
{type:"verb_table",title:"Konzessivs\u00e4tze: Konzessive Konjunktionen",groups:[{label:"Subordinierend (Verb ans Ende)",rows:[{pronoun:"obgleich",form:"Obgleich er dagegen war, stimmte er zu.",src:"Although he was against it, he agreed."},{pronoun:"wenngleich",form:"Wenngleich es schwer ist, bleibt es n\u00f6tig.",src:"Even though it is hard, it remains necessary."},{pronoun:"wenn auch",form:"Wenn auch nicht alle zustimmen...",src:"Even if not all agree..."},{pronoun:"selbst wenn",form:"Selbst wenn wir verlieren, war es richtig.",src:"Even if we lose, it was right."}]},{label:"Konnektivadverbien (Verb an Position 2)",rows:[{pronoun:"nichtsdestotrotz",form:"..., nichtsdestotrotz m\u00fcssen wir...",src:"nevertheless we must..."},{pronoun:"nichtsdestoweniger",form:"..., nichtsdestoweniger bleibt...",src:"nonetheless... remains..."},{pronoun:"trotz alledem",form:"Trotz alledem glaube ich...",src:"Despite all that, I believe..."}]}]},
{type:"tip",title:"Konzessivs\u00e4tze: Die Kunst des Einr\u00e4umens",text:"Obwohl (B1) means 'although.' At B2 level, the following are added:\nobgleich (literary 'although'), wenngleich (even though/albeit),\nwenn auch (even if), selbst wenn (even if, strongest).\n\nAll are subordinating: verb goes to the end.\nThe adverbs (nichtsdestotrotz, trotz alledem) are NOT subordinating:\nthey stand in position 1 with the verb in position 2.\n\nExample: 'Obgleich er dagegen war, stimmte er zu.'\nvs. 'Er war dagegen, nichtsdestotrotz stimmte er zu.'\nSame meaning, different grammar.",deepDive:{title:"Concessive spectrum",text:"From weakest to strongest concession: obwohl (B1 standard) < obgleich (literary) < wenngleich (elevated, 'even though') < wenn auch (flexible) < selbst wenn (strongest, 'even if in the worst case'). The adverbs nichtsdestotrotz and nichtsdestoweniger are not subordinating conjunctions but connective adverbs. They take position 1 with verb inversion, unlike the subordinating conjunctions which send the verb to the end."}},
{type:"mc",q:"Welcher Satz verwendet einen Konzessivsatz korrekt?",opts:["Obgleich die Debatte hitzig war, blieb respektvoll der Ton.","Die Debatte war hitzig obgleich, der Ton blieb respektvoll.","Obgleich die Debatte hitzig war, blieb der Ton respektvoll.","Obgleich die Debatte war hitzig, blieb der Ton respektvoll."],ans:"Obgleich die Debatte hitzig war, blieb der Ton respektvoll.",hint:"A subordinating conjunction sends the verb to the end of its clause. Check each option: only one correctly places the verb in both the subordinate and main clause."},
{type:"drag_fill",s:"Das Argument ist {1} \u00fcberzeugend, {2} l\u00e4sst es sich widerlegen.",blanks:{"1":"zwar","2":"aber"},pool:["zwar","aber","obgleich","wenngleich","sowohl","sodass"],hint:"A two-part concessive structure: the first word signals a conceded point, the second introduces the contrasting counterargument."},
{type:"match",pairs:[{trg:"obgleich",src:"although (literary)"},{trg:"selbst wenn",src:"even if (strongest)"},{trg:"nichtsdestotrotz",src:"nevertheless"},{trg:"trotz alledem",src:"despite all that"}]},
{type:"mc",q:"Was bedeutet 'die Schlussfolgerung'?",opts:["to concede, to admit","nevertheless, nonetheless","even if, although","the conclusion, the inference"],ans:"the conclusion, the inference",hint:"Schluss (end) + Folgerung (deduction). The logical result you draw at the end."},
{type:"fb",s:"Ja, {1} wurde ver\\u00f6ffentlicht.",a:["die Stellungnahme"],opts:["die Stellungnahme","nichtsdestotrotz","wenngleich","selbst wenn"],hint:"Stellung (position) + Nahme (taking). Formally taking a position on an issue.",sSrc:"Yes, the statement was published."},
{type:"mc",q:"Was bedeutet 'die Kompromissbereitschaft'?",opts:["the premise","to concede, to admit","willingness to compromise","consequently, as a result"],ans:"willingness to compromise",hint:"Kompromiss + Bereitschaft (readiness). Being ready to find middle ground."},
{type:"fb",s:"Ihre {1} hat sich über die Jahre gefestigt.",a:["Überzeugung"],opts:["Überzeugung","Schlussfolgerung","Stellungnahme","Kompromissbereitschaft"],hint:"A deeply held belief or conviction. Not a conclusion drawn from evidence, but something you firmly believe.",sSrc:"Her conviction has solidified over the years."}
]},
{id:"deu_r29l5",title:"Die Frage",icon:"\u2753",xp:15,board:true,steps:[
{type:"intro",title:"Die Frage",desc:"Verumius stands up and asks his question. In German. In front of everyone. Learn discourse markers that structure your arguments and the elegant technique of wenn-less conditionals.",goals:["Discourse markers for structured argumentation","Uninverted wenn clauses (verb-first conditionals)","The milestone experience: speaking publicly in German"]},
{type:"teach",trg:"vor allem",src:"above all, especially",pos:"adv",gender:null,note:"Vor (before) + allem (everything). Prioritizing marker.\nSignals: this point matters most.",example:"A: Was ist jetzt am wichtigsten?\nB: Vor allem müssen wir zuhören.\nA: Vor allem den Betroffenen?\nB: Ja, vor allem ihnen.",exampleSrc:"A: What is most important now?\nB: Above all, we must listen.\nA: Above all to those affected?\nB: Yes, above all to them.",funFact:"Vor (before) + allem (everything). Above all. 'Vor allem müssen wir zuhören' (Above all, we must listen). A prioritizing marker: this point matters most. Position 1 or Mittelfeld."},
{type:"mc",q:"Was ist jetzt am wichtigsten? Vor allem m\u00fcssen wir zuh\u00f6ren. Was signalisiert 'vor allem'?",opts:["Dieser Punkt ist der wichtigste von allen","Alle Punkte sind gleich wichtig","Keiner der Punkte ist wirklich wichtig","Nur der n\u00e4chste Punkt z\u00e4hlt"],ans:"Dieser Punkt ist der wichtigste von allen",hint:"Vor (before) + allem (everything). A prioritizing marker that places one argument above all others."},
{type:"teach",trg:"insbesondere",src:"in particular, especially",pos:"adv",gender:null,note:"In + besondere (particular). More formal than 'vor allem.'\nAcademic and political standard.",example:"A: Wer ist betroffen?\nB: Insbesondere junge Familien.\nA: Insbesondere in Großstädten?\nB: Ja, dort ist die Lage besonders schwierig.",exampleSrc:"A: Who is affected?\nB: Young families in particular.\nA: Especially in big cities?\nB: Yes, the situation is particularly difficult there.",funFact:"In + besondere (particular). In particular, especially. 'Insbesondere für Neuankömmlinge ist Integration wichtig.' More formal than 'vor allem.' Academic and political standard."},
{type:"teach",trg:"dar\u00fcber hinaus",src:"furthermore, beyond that",pos:"adv",gender:null,note:"Darüber (about/over that) + hinaus (beyond).\nThe additive marker: there is more beyond what was just said.",example:"A: Die Bildung muss verbessert werden.\nB: Dar\u00fcber hinaus brauchen wir mehr Ausbildungsplaetze.\nA: Dar\u00fcber hinaus auch mehr Sprachkurse?\nB: Ja, das gehört dazu.",exampleSrc:"A: Education must be improved.\nB: Furthermore, we need more training positions.\nA: Beyond that, also more language courses?\nB: Yes, that is part of it.",funFact:"Darüber (about/over that) + hinaus (beyond). Furthermore, beyond that. 'Darüber hinaus sollten wir die strukturellen Probleme beachten.' The additive marker that says: there is more beyond what was just said."},
{type:"teach",trg:"au\u00dferdem",src:"besides, moreover",pos:"adv",gender:null,note:"Ausser (outside/besides) + dem (that). More conversational\nthan 'darüber hinaus.' The everyday 'in addition.'",example:"A: Wir brauchen mehr Dialog.\nB: Au\u00dferdem mehr Geduld.\nA: Au\u00dferdem möchte ich anmerken...\nB: Bitte, fahren Sie fort.",exampleSrc:"A: We need more dialogue.\nB: Besides, more patience.\nA: Moreover, I would like to note...\nB: Please, continue.",funFact:"Ausser (outside/besides) + dem (that). Besides, moreover. 'Ausserdem möchte ich anmerken, dass...' More conversational than 'darüber hinaus.' The everyday 'in addition.'"},
{type:"teach",trg:"nicht zuletzt",src:"not least, last but not least",pos:"adv",gender:null,note:"Nicht (not) + zuletzt (lastly). Signals: this point,\nthough mentioned last, is NOT least important.",example:"A: Warum war die Debatte wichtig?\nB: Nicht zuletzt wegen der Bürgerbeteiligung.\nA: Nicht zuletzt auch wegen der Medien?\nB: Ja, die Berichterstattung war fair.",exampleSrc:"A: Why was the debate important?\nB: Not least because of citizen participation.\nA: Not least also because of the media?\nB: Yes, the reporting was fair.",funFact:"Nicht (not) + zuletzt (lastly). Not least. 'Nicht zuletzt dank der Freiwilligen.' Signals that this point, though mentioned last, is not least important."},
{type:"teach",trg:"des Weiteren",src:"furthermore (formal)",pos:"adv",gender:null,note:"Des (of the) + Weiteren (further). Highly formal.\nWritten register only: academic papers, official speeches.",example:"A: Der Bericht zeigt Fortschritte.\nB: Des Weiteren ist zu bemerken, dass die Zahlen steigen.\nA: Des Weiteren empfiehlt der Ausschuss...\nB: Welche Empfehlung genau?",exampleSrc:"A: The report shows progress.\nB: Furthermore, it should be noted that the numbers are rising.\nA: Furthermore, the committee recommends...\nB: Which recommendation exactly?",funFact:"Des (of the) + Weiteren (further). Furthermore. 'Des Weiteren ist zu bemerken, dass...' Highly formal. Written register only. Academic papers, official speeches, legal texts. The elevated 'furthermore.'"},
{type:"match",pairs:[{trg:"dar\u00fcber hinaus",src:"furthermore, beyond that"},{trg:"au\u00dferdem",src:"besides, moreover"},{trg:"nicht zuletzt",src:"not least, last but not least"},{trg:"des Weiteren",src:"furthermore (formal)"}]},
{type:"teach",trg:"allerdings",src:"however, though",pos:"adv",gender:null,note:"From 'aller Dinge' (of all things). Softer than 'jedoch.'\nIntroduces a qualification without full contradiction.",example:"A: Die Ergebnisse sind positiv.\nB: Allerdings muss man auch die Risiken sehen.\nA: Allerdings stimmt das nicht ganz.\nB: In welchem Punkt?",exampleSrc:"A: The results are positive.\nB: However, one must also see the risks.\nA: Though, that is not entirely correct.\nB: In which regard?",funFact:"The gentlest 'however' in German. 'Allerdings muss man auch bedenken, dass...' introduces a qualification without full contradiction. Softer than 'jedoch,' it traces back to 'aller Dinge' (of all things)."},
{type:"teach",trg:"trotzdem",src:"nevertheless, despite that",pos:"adv",gender:null,note:"Trotz (despite) + dem (that). Position 1 with verb inversion.\nThe everyday 'nichtsdestotrotz.' Simpler, equally effective.",example:"A: Die Lage ist schwierig.\nB: Trotzdem bleibe ich optimistisch.\nA: Trotzdem müssen wir weitermachen?\nB: Ja, gerade deshalb.",exampleSrc:"A: The situation is difficult.\nB: Nevertheless, I remain optimistic.\nA: Despite that, we must continue?\nB: Yes, precisely because of that.",funFact:"Trotz (despite) + dem (that). Nevertheless, despite that. 'Trotzdem bleibe ich optimistisch.' Position 1 with verb inversion. The everyday 'nichtsdestotrotz.' Simpler, less formal, equally effective."},
{type:"teach",trg:"folglich",src:"consequently, therefore",pos:"adv",gender:null,note:"From 'folgen' (to follow). The logical conclusion marker.\nShort and authoritative.",example:"A: Die Mehrheit hat zugestimmt.\nB: Folglich tritt das Gesetz in Kraft.\nA: Folglich müssen wir uns anpassen?\nB: Ja, ab sofort.",exampleSrc:"A: The majority agreed.\nB: Consequently, the law takes effect.\nA: Therefore, we must adapt?\nB: Yes, effective immediately.",funFact:"Short, authoritative, and final: 'Folglich m\u00fcssen wir handeln.' (Consequently, we must act.) The logical conclusion marker. What follows from the evidence. Built on 'folgen' (to follow)."},
{type:"teach",trg:"zugegebenerma\u00dfen",src:"admittedly",pos:"adv",gender:null,note:"Zugegeben (admitted) + -ermassen (in a manner).\nYou admit something before arguing against it.",example:"A: Ist das Problem ernst?\nB: Zugegebenerma\u00dfen ja.\nA: Zugegebenerma\u00dfen ist die Lage kompliziert.\nB: Aber nicht hoffnungslos.",exampleSrc:"A: Is the problem serious?\nB: Admittedly, yes.\nA: Admittedly, the situation is complicated.\nB: But not hopeless.",funFact:"Zugegeben (admitted) + -ermassen (in a manner). Admittedly. 'Zugegebenermassen ist die Lage kompliziert.' You admit something before arguing against it. The honest concession marker."},
{type:"mc",q:"Der Erfolg war {blank} auch den Freiwilligen zu verdanken.",opts:["nicht zuletzt","trotzdem","folglich","zugegebenermaßen"],ans:"nicht zuletzt",hint:"A phrase meaning 'last but not least' or 'not least.' It highlights an important contributing factor."}
]},
{id:"deu_r29l5b",title:"Die Frage (Teil 2)",icon:"\u2753",xp:15,board:true,steps:[
{type:"intro",title:"Die Frage (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"wohlgemerkt",src:"mind you, note well",pos:"adv",gender:null,note:"Wohl (well) + gemerkt (noted). An interjection that inserts\nan important qualification. 'Pay attention to this detail.'",example:"A: Er hat keine Erfahrung.\nB: Wohlgemerkt, er hat erst angefangen.\nA: Wohlgemerkt, das war sein erster Versuch.\nB: Und trotzdem recht erfolgreich.",exampleSrc:"A: He has no experience.\nB: Mind you, he just started.\nA: Mind you, that was his first attempt.\nB: And still quite successful.",funFact:"Wohl (well) + gemerkt (noted). Mind you, note well. 'Er hat, wohlgemerkt, keine Erfahrung in diesem Bereich.' An interjection that inserts an important qualification. Pay attention to this detail."},
{type:"teach",trg:"kurzum",src:"in short, in a nutshell",pos:"adv",gender:null,note:"Kurz (short) + um (around). The summary marker.\nEverything condensed into one sentence.",example:"A: Wie war die Debatte?\nB: Kurzum: ein Erfolg.\nA: Kurzum, wir brauchen einen Kompromiss.\nB: Dem stimme ich zu.",exampleSrc:"A: How was the debate?\nB: In short: a success.\nA: In a nutshell, we need a compromise.\nB: I agree with that.",funFact:"Kurz (short) + um (around). In short, in a nutshell. 'Kurzum: Wir brauchen einen Kompromiss.' The summary marker. Everything said before condensed into one sentence."},
{type:"teach",trg:"die Gegenposition",src:"counterposition",pos:"noun",gender:"f",note:"Gegen (against) + Position. The formal way to present\nthe opposing view. Neutral: it is a position, not an attack.",example:"A: Was ist die Gegenposition?\nB: Die Gegenposition lautet: Integration ist Aufgabe des Staates.\nA: Wer vertritt diese Gegenposition?\nB: Vor allem die linken Parteien.",exampleSrc:"A: What is the counterposition?\nB: The counterposition is: integration is the state's task.\nA: Who represents this counterposition?\nB: Above all, the left-wing parties.",funFact:"Gegen (against) + Position. Die Gegenposition. The formal way to present the opposing view. 'Die Gegenposition lautet...' Neutral: it is a position, not an attack."},
{type:"teach",trg:"der Gegenvorschlag",src:"counterproposal",pos:"noun",gender:"m",note:"Gegen + Vorschlag (proposal). More constructive than\nGegenargument. Not just against, but offering an alternative.",example:"A: Der Vorschlag wurde abgelehnt.\nB: Haben Sie einen Gegenvorschlag?\nA: Mein Gegenvorschlag wäre ein Pilotprojekt.\nB: Das klingt vernuenftig.",exampleSrc:"A: The proposal was rejected.\nB: Do you have a counterproposal?\nA: My counterproposal would be a pilot project.\nB: That sounds reasonable.",funFact:"Gegen + Vorschlag (proposal). Der Gegenvorschlag. A counterproposal. 'Ich habe einen Gegenvorschlag.' More constructive than Gegenargument. Not just against, but offering an alternative."},
{type:"teach",trg:"die Meinungsbildung",src:"opinion formation",pos:"noun",gender:"f",note:"Meinung (opinion) + Bildung (formation/education).\nThe process by which citizens form opinions. Democracy depends on it.",example:"A: Wie bilden Sie sich Ihre Meinung?\nB: Durch Medien und Diskussionen.\nA: Freie Meinungsbildung ist ein Grundrecht.\nB: Ja, ohne sie keine Demokratie.",exampleSrc:"A: How do you form your opinion?\nB: Through media and discussions.\nA: Free opinion formation is a fundamental right.\nB: Yes, without it no democracy.",funFact:"Meinung (opinion) + Bildung (formation/education). Die Meinungsbildung. Opinion formation. 'Freie Meinungsbildung ist ein Grundrecht.' The process by which citizens form opinions. Democracy depends on informed Meinungsbildung."},
{type:"match",pairs:[{trg:"kurzum",src:"in short, in a nutshell"},{trg:"die Gegenposition",src:"counterposition"},{trg:"der Gegenvorschlag",src:"counterproposal"},{trg:"die Meinungsbildung",src:"opinion formation"}]},
{type:"teach",trg:"das Stimmrecht",src:"right to vote",pos:"noun",gender:"n",note:"Stimm (voice/vote) + Recht (right). Your voice IS your right.\nWomen gained Stimmrecht in Germany in 1918.",example:"A: Wer hat Stimmrecht?\nB: Alle Bürger ab 18 Jahren.\nA: Gilt das Stimmrecht auch für Kommunalwahlen?\nB: Ja, auch EU-Bürger haben dort Stimmrecht.",exampleSrc:"A: Who has the right to vote?\nB: All citizens from age 18.\nA: Does the right to vote apply to local elections too?\nB: Yes, EU citizens also have voting rights there.",funFact:"Stimm (voice/vote) + Recht (right). Das Stimmrecht. The right to vote. 'Allgemeines Stimmrecht' (universal suffrage). Your voice IS your right. Women gained Stimmrecht in Germany in 1918."},
{type:"teach",trg:"das Zugest\u00e4ndnis",src:"concession",pos:"noun",gender:"n",note:"From 'zugestehen' (to concede). Not weakness, but strategic\nflexibility. Every coalition requires Zugeständnisse.",example:"A: Gibt es einen Kompromiss?\nB: Nur mit Zugest\u00e4ndnissen von beiden Seiten.\nA: Welches Zugest\u00e4ndnis erwarten Sie?\nB: Die Regierung muss nachgeben.",exampleSrc:"A: Is there a compromise?\nB: Only with concessions from both sides.\nA: What concession do you expect?\nB: The government must give in.",funFact:"Every German coalition requires Zugest\u00e4ndnisse from all parties. 'Ein Zugest\u00e4ndnis machen' (to make a concession) is not weakness but strategic flexibility. The root 'zugestehen' means to concede, to grant."},
{type:"teach",trg:"dagegenhalten",src:"to counter, to object",pos:"verb",gender:null,note:"Dagegen (against it) + halten (to hold). Separable.\nYou hold your position AGAINST theirs.",example:"A: Das Argument ist stark.\nB: Dem ist dagegenzuhalten, dass die Daten veraltet sind.\nA: Was halten Sie dagegen?\nB: Neuere Studien zeigen das Gegenteil.",exampleSrc:"A: The argument is strong.\nB: To counter that, the data is outdated.\nA: What do you hold against it?\nB: Newer studies show the opposite.",funFact:"Dagegen (against it) + halten (to hold). To counter, to object. 'Dem ist dagegenzuhalten, dass...' (The objection to that is that...). Separable. You hold your position AGAINST theirs."},
{type:"teach",trg:"erwidern",src:"to reply, to respond",pos:"verb",gender:null,note:"From 'wider' (against). Not separable. More formal than\nantworten. Implies a substantive response.",example:"A: Was hat der Panelist gesagt?\nB: Er erwiderte: 'Das sehe ich anders.'\nA: Wie erwidern Sie den Vorwurf?\nB: Mit Fakten und Belegen.",exampleSrc:"A: What did the panelist say?\nB: He replied: 'I see that differently.'\nA: How do you respond to the accusation?\nB: With facts and evidence.",funFact:"More formal than antworten and implying a substantive response, not just acknowledgment. 'Er erwiderte ruhig: Das sehe ich anders.' Not separable. The prefix 'wider' (against) hints at a reply that pushes back."},
{type:"teach",trg:"opponieren",src:"to oppose",pos:"verb",gender:null,note:"From Latin 'opponere' (to place against). Formal, political.\nThe verb form of Opposition.",example:"A: Wer opponiert gegen den Entwurf?\nB: Die gesamte Opposition.\nA: Warum opponieren sie?\nB: Sie halten den Entwurf für ungerecht.",exampleSrc:"A: Who opposes the bill?\nB: The entire opposition.\nA: Why do they oppose it?\nB: They consider the bill unjust.",funFact:"The verb form of Opposition, standard in political discourse but rare in everyday speech. 'Die Fraktion opponiert gegen den Entwurf.' Latin 'opponere' means to place against, which captures the confrontational stance."},
{type:"match",pairs:[{trg:"das Zugest\u00e4ndnis",src:"concession"},{trg:"dagegenhalten",src:"to counter, to object"},{trg:"erwidern",src:"to reply, to respond"},{trg:"opponieren",src:"to oppose"}]},
{type:"teach",trg:"würde",src:"would (Konjunktiv II of werden)",pos:"verb",gender:null,note:"Konjunktiv II of 'werden'. Used for polite requests\nand hypothetical statements: 'Ich würde...'",example:"A: Was würdest du anders machen?\nB: Ich würde frühzeitig handeln.\nA: Würde mehr Dialog helfen?\nB: Ja, das würde sehr helfen.",exampleSrc:"A: What would you do differently?\nB: I would act early.\nA: Would more dialogue help?\nB: Yes, that would help a lot.",funFact:"Würde is the Konjunktiv II form of werden. It works like English 'would': würde + Infinitiv = polite or hypothetical. In uneingeleiteten Konditionalsaetzen (verb-first conditionals), würde appears in the main clause: 'Hätte ich Zeit, würde ich kommen.'"},
{type:"tip",title:"Uneingeleitete wenn-Saetze: Wenn weglassen",text:"In formal German, 'wenn' can be omitted and the verb placed in position 1.\n\nWith wenn: Wenn ich mehr Zeit hätte, würde ich kommen.\nWithout wenn: Hätte ich mehr Zeit, würde ich kommen.\n\nThe meaning is identical. The register is elevated.\n\nHow to recognize it: verb in position 1 + Konjunktiv II = conditional clause without wenn.\n\nExamples:\n- Wäre es möglich, würde ich zustimmen.\n- Hätten wir früher gehandelt, wäre es besser.\n- Könnten alle teilnehmen, wäre die Debatte reicher.\n\nCommon in speeches, essays, and formal argumentation."},
{type:"mc",q:"'Wäre es nicht zutreffender, Integration als gegenseitigen Prozess zu sehen?' Was macht diesen Satz zu einem Konditionalsatz ohne 'wenn'?",opts:["Das Verb (wäre) steht an erster Stelle und bildet ohne wenn eine Bedingung","Konjunktiv II lässt immer wenn automatisch weg","Es ist eine rhetorische Frage, die keinen grammatischen Sonderstatus besitzt","Das Subjekt folgt dem Verb, also ist es ein Imperativ"],ans:"Das Verb (wäre) steht an erster Stelle und bildet ohne wenn eine Bedingung",hint:"Look at where the finite action word appears in the first clause. An unusual placement combined with a subjunctive mood can replace a conditional connector."},
{type:"fb",s:"{1} die Opposition zugestimmt, wäre der Kompromiss möglich gewesen.",a:["H\u00e4tte"],opts:["Wenn","H\u00e4tte","Hat","W\u00fcrde"],hint:"Verb-first conditional without 'wenn'. The subject is 'die Opposition'. Which Konjunktiv II form of the auxiliary verb for agreement goes to position 1?",sSrc:"Had the opposition agreed, the compromise would have been possible."},
{type:"drag_fill",s:"{1} ist die Lage komplex. {2} müssen wir handeln.",blanks:{"1":"Zugegebenermassen","2":"Nichtsdestotrotz"},pool:["Zugegebenermassen","Nichtsdestotrotz","Obgleich","Deshalb","Weder","Kurzum"],hint:"First honestly acknowledge the difficulty, then nevertheless emphasize the need to act."},
{type:"mc",q:"Was bedeutet 'wohlgemerkt'?",opts:["mind you, note well","would (Konjunktiv II of werden)","furthermore, beyond that","admittedly"],ans:"mind you, note well",hint:"wohl (indeed) + gemerkt (noticed). An interjection: pay close attention to this!"},
{type:"fb",s:"Was ist {1}?",a:["die Gegenposition"],opts:["die Gegenposition","der Gegenvorschlag","kurzum","würde"],hint:"Gegen (against) + Position. The stance that opposes the current one.",sSrc:"What is the counterposition?"},
{type:"mc",q:"Was bedeutet 'der Gegenvorschlag'?",opts:["opinion formation","mind you, note well","consequently, therefore","counterproposal"],ans:"counterproposal",hint:"Gegen (against) + Vorschlag (proposal). An alternative offered in response."},
{type:"fb",s:"Wie sagt man 'opinion formation' auf Deutsch? {1}",a:["die Meinungsbildung"],opts:["allerdings","vor allem","erwidern","die Meinungsbildung"],hint:"Meinung (opinion) + Bildung (formation/education). How opinions take shape.",sSrc:"How do you say 'opinion formation' in German?"},
{type:"mc",q:"Was bedeutet 'das Stimmrecht'?",opts:["counterproposal","right to vote","to counter, to object","to oppose"],ans:"right to vote",hint:"Stimme (voice) + Recht (entitlement). The fundamental democratic privilege in elections."},
{type:"fb",s:"Wie sagt man 'to counter, to object' auf Deutsch? {1}",a:["dagegenhalten"],opts:["dagegenhalten","vor allem","insbesondere","erwidern"],hint:"dagegen (against it) + halten (to hold). To hold a position against something.",sSrc:"How do you say 'to counter, to object' in German?"},
{type:"mc",q:"Was bedeutet 'erwidern'?",opts:["to oppose","would (Konjunktiv II of werden)","besides, moreover","to reply, to respond"],ans:"to reply, to respond",hint:"From wider (against/back). A formal way to answer back in debate."},
{type:"fb",s:"Warum {1} sie?",a:["opponieren"],opts:["opponieren","dagegenhalten","die Gegenposition","das Stimmrecht"],hint:"Latin loan: from opponere (to set against). Cognate of English 'oppose'.",sSrc:"Why do they oppose it?"}
]},
{id:"deu_r29l6",title:"Zwischenrufe und Repliken",icon:"\ud83d\udde3\ufe0f",xp:15,board:true,steps:[
{type:"intro",title:"Zwischenrufe und Repliken",desc:"The debate intensifies. Verumius's question has opened a new thread. Learn formal comparison markers and practice all three grammar constructs in debate contexts.",goals:["Master formal comparison markers","Practice all three grammar constructs in combination","Express nuanced agreement and disagreement"]},
{type:"teach",trg:"im Vergleich zu",src:"in comparison to/with",pos:"adv",gender:null,note:"Im (in the) + Vergleich (comparison) + zu (to).\nThe standard formal comparison frame.",example:"A: Wie steht Deutschland da?\nB: Im Vergleich zu Frankreich gut.\nA: Im Vergleich zu letztem Jahr?\nB: Deutlich besser.",exampleSrc:"A: How does Germany stand?\nB: In comparison to France, well.\nA: Compared to last year?\nB: Significantly better.",funFact:"Im (in the) + Vergleich (comparison) + zu (to). In comparison to/with. 'Im Vergleich zu letztem Jahr sind die Zahlen besser.' The standard formal comparison frame. Opens with context, then delivers the contrast."},
{type:"mc",q:"Wie steht Deutschland im Vergleich zu anderen L\u00e4ndern? Was signalisiert 'im Vergleich zu'?",opts:["Einen formellen Vergleichsrahmen","Eine Konzession mit Einschr\u00e4nkung","Eine logische Schlussfolgerung","Eine Bedingung ohne wenn"],ans:"Einen formellen Vergleichsrahmen",hint:"Im (in the) + Vergleich (comparison) + zu (to). The standard formal frame for placing two things side by side."},
{type:"teach",trg:"verglichen mit",src:"compared with",pos:"adv",gender:null,note:"Past participle 'verglichen' (compared) + mit (with).\nShorter than 'im Vergleich zu.' Same meaning.",example:"A: Verglichen mit anderen Ländern...\nB: ...ist das System hier effizient.\nA: Verglichen mit der Vergangenheit?\nB: Grosser Fortschritt.",exampleSrc:"A: Compared with other countries...\nB: ...the system here is efficient.\nA: Compared with the past?\nB: Great progress.",funFact:"Past participle 'verglichen' (compared) + mit (with). Compared with. 'Verglichen mit anderen Ländern ist das System effizient.' Shorter than 'im Vergleich zu.' Same meaning, different grammar (participle construction)."},
{type:"teach",trg:"genauso wie",src:"just like, in the same way as",pos:"adv",gender:null,note:"Genauso (just as) + wie (as). The equality marker:\nX is the same as Y.",example:"A: Betrifft Integration nur Neuankömmlinge?\nB: Nein, Einheimische genauso wie Neuankömmlinge.\nA: Genauso wie bei der Sprache?\nB: Ja, Dialog geht in beide Richtungen.",exampleSrc:"A: Does integration only affect newcomers?\nB: No, locals just like newcomers.\nA: Just like with language?\nB: Yes, dialogue goes in both directions.",funFact:"Genauso (just as) + wie (as). Just like. 'Integration betrifft Einheimische genauso wie Neuankömmlinge.' The equality marker: X is the same as Y."},
{type:"teach",trg:"anders als",src:"unlike, different from",pos:"adv",gender:null,note:"Anders (differently) + als (than). The contrast marker:\nX is NOT like Y. Short, direct, common.",example:"A: Ist es hier wie in Frankreich?\nB: Nein, anders als in Frankreich gibt es hier kein Kopftuchverbot.\nA: Anders als erwartet?\nB: Ja, die Debatte war konstruktiv.",exampleSrc:"A: Is it like in France here?\nB: No, unlike in France, there is no headscarf ban here.\nA: Unlike expected?\nB: Yes, the debate was constructive.",funFact:"Anders (differently) + als (than). Unlike, different from. 'Anders als erwartet war die Debatte konstruktiv.' The contrast marker: X is NOT like Y. Short, direct, common in speech and writing."},
{type:"fb",s:"{1} als in Frankreich gibt es in Deutschland keinen strikten Laizismus.",a:["Anders"],opts:["Genauso","Anders","Verglichen","Gleicherma\u00dfen"],hint:"The comparison marker that signals X is NOT like Y. Introduces a contrast with another country.",sSrc:"Unlike in France, there is no strict secularism in Germany."},
{type:"teach",trg:"\u00e4hnlich wie",src:"similar to",pos:"adv",gender:null,note:"Aehnlich (similar) + wie (as). Not identical, but comparable.\nThe approximation marker.",example:"A: Ist das System hier ähnlich wie in Oesterreich?\nB: \u00c4hnlich wie dort gibt es eine Koalitionsregierung.\nA: \u00c4hnlich wie beim letzten Mal?\nB: Ja, aber mit neuen Partnern.",exampleSrc:"A: Is the system here similar to Austria?\nB: Similar to there, there is a coalition government.\nA: Similar to last time?\nB: Yes, but with new partners.",funFact:"Aehnlich (similar) + wie (as). Similar to. 'Aehnlich wie in Oesterreich gibt es auch hier eine Koalitionsregierung.' Not identical, but comparable. The approximation marker."},
{type:"teach",trg:"im Unterschied zu",src:"in contrast to, unlike",pos:"adv",gender:null,note:"Im (in the) + Unterschied (difference) + zu (to).\nFormal, written register. Points to a specific difference.",example:"A: Im Unterschied zu früheren Debatten...\nB: ...war diese sachlich und respektvoll.\nA: Im Unterschied zu anderen Ländern?\nB: Deutschland setzt auf Foederalismus.",exampleSrc:"A: In contrast to earlier debates...\nB: ...this one was factual and respectful.\nA: In contrast to other countries?\nB: Germany relies on federalism.",funFact:"Im (in the) + Unterschied (difference) + zu (to). In contrast to, unlike. 'Im Unterschied zu früheren Debatten war diese sachlich.' Formal, written register. Points to a specific difference."},
{type:"teach",trg:"im Gegensatz zu",src:"in contrast to, as opposed to",pos:"adv",gender:null,note:"Im (in the) + Gegensatz (contrast/opposite) + zu (to).\nStronger contrast than 'im Unterschied zu.'",example:"A: Was ist Ihre Position?\nB: Im Gegensatz zu meinem Vorredner bin ich optimistisch.\nA: Im Gegensatz zu den Umfragen?\nB: Ja, ich sehe Fortschritte.",exampleSrc:"A: What is your position?\nB: In contrast to my predecessor, I am optimistic.\nA: As opposed to the polls?\nB: Yes, I see progress.",funFact:"Im (in the) + Gegensatz (contrast/opposite) + zu (to). In contrast to, as opposed to. 'Im Gegensatz zu meinem Vorredner bin ich optimistisch.' Stronger contrast than 'im Unterschied zu.' Almost adversarial."},
{type:"teach",trg:"demgegen\u00fcber",src:"in contrast to that, on the other hand",pos:"adv",gender:null,note:"Dem (that) + gegenüber (opposite/across from).\nFormal connective adverb. Points to the other side.",example:"A: Die Regierung ist zuversichtlich.\nB: Demgegen\u00fcber steht die Skepsis der Opposition.\nA: Demgegen\u00fcber gibt es auch positive Stimmen.\nB: Das stimmt.",exampleSrc:"A: The government is confident.\nB: In contrast, there is the opposition's skepticism.\nA: On the other hand, there are positive voices too.\nB: That is true.",funFact:"Dem (that) + gegenüber (opposite/across from). In contrast to that. 'Demgegenüber steht die Position der Opposition.' Formal connective adverb. Points across to the other side of the argument."},
{type:"teach",trg:"gleicherma\u00dfen",src:"equally, in equal measure",pos:"adv",gender:null,note:"Gleicher (equal) + massen (measure). Everything in equal\nportion. Formal and precise. The fairness adverb.",example:"A: Wer ist betroffen?\nB: Alle Bürger gleicherma\u00dfen.\nA: Gleicherma\u00dfen Maenner und Frauen?\nB: Ja, ohne Unterschied.",exampleSrc:"A: Who is affected?\nB: All citizens equally.\nA: Men and women equally?\nB: Yes, without distinction.",funFact:"Gleicher (equal) + massen (measure). Equally, in equal measure. 'Das betrifft alle Bürger gleichermassen.' Everything in equal portion. Formal and precise. The fairness adverb."},
{type:"mc",q:"Im Gegensatz zu meinem Vorredner bin ich optimistisch. Was signalisiert 'im Gegensatz zu'?",opts:["Eine zeitliche Abfolge von Ereignissen","Eine Ursache-Wirkungs-Beziehung","Einen starken Kontrast zum vorherigen Sprecher","Eine \u00dcbereinstimmung mit dem Vorredner"],ans:"Einen starken Kontrast zum vorherigen Sprecher",hint:"Im (in the) + Gegensatz (opposite/contrast) + zu (to). A formal comparison marker signaling that the speaker takes the opposing view."}
]},
{id:"deu_r29l6b",title:"Zwischenrufe und Repliken (Teil 2)",icon:"\ud83d\udde3\ufe0f",xp:15,board:true,steps:[
{type:"intro",title:"Zwischenrufe und Repliken (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"ungeachtet dessen",src:"regardless of that, notwithstanding",pos:"adv",gender:null,note:"Ungeachtet (disregarded) + dessen (of that). Legal register.\nThe strongest 'regardless': it does not change my conclusion.",example:"A: Es gibt Kritik am Verfahren.\nB: Ungeachtet dessen bleibt die Entscheidung gueltig.\nA: Ungeachtet dessen müssen wir weitermachen?\nB: Ja, die Grundrechte gelten trotzdem.",exampleSrc:"A: There is criticism of the process.\nB: Regardless of that, the decision remains valid.\nA: Notwithstanding, we must continue?\nB: Yes, fundamental rights apply nonetheless.",funFact:"Ungeachtet (disregarded) + dessen (of that). Regardless of that, notwithstanding. 'Ungeachtet dessen bleiben die Grundrechte bestehen.' Legal register. The strongest 'regardless.'"},
{type:"teach",trg:"in Anbetracht",src:"in view of, considering",pos:"adv",gender:null,note:"In + Anbetracht (consideration/view). Formal framing phrase.\nSets the context before the judgment. Takes genitive.",example:"A: Wie sehen Sie die Lage?\nB: In Anbetracht der Umstände war die Entscheidung richtig.\nA: In Anbetracht der Kosten?\nB: Auch finanziell vertretbar.",exampleSrc:"A: How do you see the situation?\nB: In view of the circumstances, the decision was right.\nA: Considering the costs?\nB: Also financially justifiable.",funFact:"In + Anbetracht (consideration/view). In view of, considering. 'In Anbetracht der Umstände war die Entscheidung richtig.' Formal framing phrase. Sets context before judgment. Takes genitive."},
{type:"teach",trg:"die Zust\u00e4ndigkeit",src:"jurisdiction, area of responsibility",pos:"noun",gender:"f",note:"Zuständig (responsible) + -keit. Bureaucratic precision:\nwho handles what. Essential in German administration.",example:"A: Wer ist dafür zuständig?\nB: Das fällt nicht in meine Zust\u00e4ndigkeit.\nA: Wessen Zust\u00e4ndigkeit ist das?\nB: Die des Innenministeriums.",exampleSrc:"A: Who is responsible for that?\nB: That does not fall within my jurisdiction.\nA: Whose area of responsibility is that?\nB: That of the Interior Ministry.",funFact:"Zuständig (responsible/competent) + -keit. Die Zuständigkeit. Jurisdiction, area of responsibility. 'Das fällt nicht in meine Zuständigkeit.' Bureaucratic precision: who handles what."},
{type:"teach",trg:"die Volksabstimmung",src:"referendum",pos:"noun",gender:"f",note:"Volk (people) + Abstimmung (vote). Direct democracy.\nGermany rarely uses them at federal level.",example:"A: Sollte es eine Volksabstimmung geben?\nB: Über dieses Thema? Vielleicht.\nA: Volksabstimmungen sind direkte Demokratie.\nB: Ja, aber sie sind in Deutschland selten.",exampleSrc:"A: Should there be a referendum?\nB: On this topic? Perhaps.\nA: Referendums are direct democracy.\nB: Yes, but they are rare in Germany.",funFact:"Volk (people) + Abstimmung (vote). Die Volksabstimmung. A referendum. 'Eine Volksabstimmung über das Thema fordern.' Direct democracy. Germany rarely uses them at federal level. Switzerland uses them constantly."},
{type:"teach",trg:"das Wahlrecht",src:"electoral law / right to vote",pos:"noun",gender:"n",note:"Wahl (election) + Recht (right/law). 'Aktives Wahlrecht' =\nright to vote. 'Passives Wahlrecht' = right to run for office.",example:"A: Was ist aktives Wahlrecht?\nB: Das Recht zu waehlen.\nA: Und passives Wahlrecht?\nB: Das Recht, gewaehlt zu werden.",exampleSrc:"A: What is active electoral law?\nB: The right to vote.\nA: And passive electoral law?\nB: The right to be elected.",funFact:"Wahl (election) + Recht (right/law). Das Wahlrecht. Electoral law or the right to vote. 'Das aktive Wahlrecht' (the right to vote) vs. 'das passive Wahlrecht' (the right to run for office). Two rights, one word."},
{type:"match",pairs:[{trg:"in Anbetracht",src:"in view of, considering"},{trg:"die Zust\u00e4ndigkeit",src:"jurisdiction, area of responsibility"},{trg:"die Volksabstimmung",src:"referendum"},{trg:"das Wahlrecht",src:"electoral law / right to vote"}]},
{type:"teach",trg:"der Zusammenschluss",src:"merger, union, alliance",pos:"noun",gender:"m",note:"Zusammen (together) + Schluss (closing). Closing together:\nuniting. Political and business vocabulary.",example:"A: Was ist ein Zusammenschluss?\nB: Wenn mehrere Gruppen sich vereinen.\nA: Ein Zusammenschluss von Bürgerinitiativen?\nB: Ja, gemeinsam sind sie stärker.",exampleSrc:"A: What is an alliance?\nB: When several groups unite.\nA: An alliance of citizen initiatives?\nB: Yes, together they are stronger.",funFact:"Zusammen (together) + Schluss (closing). Der Zusammenschluss. A merger, a union, an alliance. 'Ein Zusammenschluss von Bürgerinitiativen.' Closing together: uniting."},
{type:"teach",trg:"der Rechtsstaat",src:"state governed by the rule of law",pos:"noun",gender:"m",note:"Recht (law/right) + Staat (state). The government itself\nis bound by law. No one is above the law.",example:"A: Was bedeutet Rechtsstaat?\nB: Dass alle, auch die Regierung, dem Gesetz folgen.\nA: Ist Deutschland ein Rechtsstaat?\nB: Ja, das ist ein Grundprinzip.",exampleSrc:"A: What does Rechtsstaat mean?\nB: That everyone, including the government, follows the law.\nA: Is Germany a Rechtsstaat?\nB: Yes, that is a fundamental principle.",funFact:"Recht (law/right) + Staat (state). Der Rechtsstaat. A state governed by the rule of law. 'Deutschland ist ein Rechtsstaat.' The government itself is bound by law. No one is above the law."},
{type:"teach",trg:"rechtsstaatlich",src:"pertaining to the rule of law",pos:"adj",gender:null,note:"Rechtsstaat + -lich. 'Rechtsstaatlich handeln' means:\nacting within the law, due process, fair procedures.",example:"A: Ist das Verfahren rechtsstaatlich?\nB: Ja, alle Regeln wurden eingehalten.\nA: Rechtsstaatliche Prinzipien sind wichtig.\nB: Sie sind die Grundlage der Demokratie.",exampleSrc:"A: Is the process lawful?\nB: Yes, all rules were followed.\nA: Rule-of-law principles are important.\nB: They are the foundation of democracy.",funFact:"Rechtsstaat + -lich. Pertaining to the rule of law. 'Rechtsstaatliche Prinzipien müssen gewahrt bleiben.' The adjective of legal order. 'Rechtsstaatlich handeln' means acting within the law."},
{type:"teach",trg:"oppositionell",src:"oppositional, relating to the opposition",pos:"adj",gender:null,note:"Opposition + -ell. The adjective for organized disagreement.\nNot negative: structurally necessary in democracy.",example:"A: Gibt es oppositionelle Stimmen?\nB: Ja, die werden lauter.\nA: Ist oppositionelles Verhalten erwuenscht?\nB: In einer Demokratie ist es notwendig.",exampleSrc:"A: Are there oppositional voices?\nB: Yes, they are getting louder.\nA: Is oppositional behavior desired?\nB: In a democracy, it is necessary.",funFact:"Opposition + -ell. Oppositional, relating to the opposition. 'Oppositionelle Stimmen werden lauter.' The adjective for the role of organized disagreement. Not negative: structurally necessary in democracy."},
{type:"fb",s:"Deutschland ist ein {1}. Alle, auch die Regierung, m\u00fcssen dem Gesetz folgen.",a:["Rechtsstaat"],opts:["Bundestag","Zusammenschluss","Wahlrecht","Rechtsstaat"],hint:"The compound noun: Recht (law) + Staat (state). A state where the rule of law governs everyone, including the government.",sSrc:"Germany is a state governed by the rule of law. Everyone, including the government, must follow the law."},
{type:"teach",trg:"zugestehen",src:"to concede, to grant",pos:"verb",gender:null,note:"Zu (to) + gestehen (to confess/admit). The act of granting\nyour opponent a valid point.",example:"A: Hat er recht?\nB: Das muss man ihm zugestehen.\nA: Sie gestehen also zu, dass...\nB: Ja, in diesem Punkt hat die Opposition recht.",exampleSrc:"A: Is he right?\nB: One must concede that to him.\nA: So you concede that...\nB: Yes, on this point the opposition is right.",funFact:"Zu (to) + gestehen (to confess/admit). To concede, to grant. 'Das muss man dem Gegner zugestehen.' The act of granting your opponent a valid point."},
{type:"teach",trg:"forcieren",src:"to push for, to accelerate",pos:"verb",gender:null,note:"From French 'forcer' (to force). Stronger than 'unterstuetzen.'\nYou actively accelerate the process.",example:"A: Die Reform geht zu langsam.\nB: Wir müssen sie forcieren.\nA: Wie wollen Sie das forcieren?\nB: Mit klaren Fristen und Maßnahmen.",exampleSrc:"A: The reform is going too slowly.\nB: We must push for it.\nA: How do you want to accelerate it?\nB: With clear deadlines and measures.",funFact:"Stronger than 'unterst\u00fctzen,' forcieren means you actively push and accelerate. 'Die Reform forcieren' implies urgency. Borrowed from French 'forcer' (to force), it adds muscle to political language."},
{type:"mc",q:"'Im Gegensatz zu früheren Generationen engagieren sich junge Menschen anders, obgleich nicht weniger intensiv.' Wie viele fortgeschrittene Strukturen sind kombiniert?",opts:["Zwei: formeller Vergleich (im Gegensatz zu) + Konzessivsatz (obgleich)","Eine: nur der Vergleichsmarker","Keine: das ist einfache B1-Grammatik","Drei: formeller Vergleich, Konzessivsatz und ein zusätzlicher Relativsatz"],ans:"Zwei: formeller Vergleich (im Gegensatz zu) + Konzessivsatz (obgleich)",hint:"Identify each distinct advanced structure in the sentence: one marks a contrast with something prior, the other concedes a point. Count them."},
{type:"fb",s:"{1} wir alle Standpunkte abgewaegt, könnten wir zu einem Kompromiss kommen.",a:["H\u00e4tten"],opts:["Wenn","H\u00e4tten","Haben","W\u00e4ren"],hint:"Verb-first conditional without 'wenn'. The verb 'abwägen' determines which auxiliary belongs here.",sSrc:"Had we weighed all viewpoints, we could reach a compromise."},
{type:"drag_fill",s:"{1} die Debatte kontrovers war, führte sie {2} zu einem Kompromiss.",blanks:{"1":"Obgleich","2":"nichtsdestotrotz"},pool:["Obgleich","nichtsdestotrotz","Weil","deshalb","Sowohl","kurzum"],hint:"Two advanced structures: a subordinating concessive conjunction opening the first clause, and a connective adverb reinforcing the contrast in the second clause."},
{type:"match",pairs:[{trg:"im Gegensatz zu",src:"as opposed to"},{trg:"verglichen mit",src:"compared with"},{trg:"genauso wie",src:"just like"},{trg:"anders als",src:"unlike"}]},
{type:"mc",q:"Was bedeutet 'ungeachtet dessen'?",opts:["electoral law / right to vote","similar to","in contrast to, as opposed to","regardless of that, notwithstanding"],ans:"regardless of that, notwithstanding",hint:"un- (not) + geachtet (regarded) + dessen (of that). Not regarding that."},
{type:"fb",s:"{1} der Umstände war die Entscheidung richtig.",a:["in Anbetracht"],opts:["in Anbetracht","der Rechtsstaat","oppositionell","genauso wie"],hint:"An- + betrachten (to consider/view). A formal phrase for 'in light of'.",sSrc:"In view of the circumstances, the decision was right."},
{type:"mc",q:"Was bedeutet 'die Volksabstimmung'?",opts:["equally, in equal measure","in comparison to/with","merger, union, alliance","referendum"],ans:"referendum",hint:"Volk (people) + Abstimmung (vote). When the whole population votes on an issue."},
{type:"fb",s:"Gibt es {1}e Stimmen?",a:["oppositionell"],opts:["im Gegensatz zu","verglichen mit","ungeachtet dessen","oppositionell"],hint:"Adjective form of Opposition. Describing voices that dissent or push back.",sSrc:"Are there oppositional voices?"},
{type:"mc",q:"Was bedeutet 'zugestehen'?",opts:["compared with","to concede, to grant","in comparison to/with","just like, in the same way as"],ans:"to concede, to grant",hint:"zu- (to) + gestehen (to confess). To acknowledge a point and yield it to the other side."},
{type:"fb",s:"Wir müssen sie {1}.",a:["forcieren"],opts:["forcieren","im Unterschied zu","der Zusammenschluss","der Rechtsstaat"],hint:"French loan word (forcer). To push hard, to accelerate with pressure.",sSrc:"We must push for it."},
{type:"fb",s:"Das fällt nicht in meine {1}.",a:["Zuständigkeit"],opts:["Zuständigkeit","Stellungnahme","Verfassung","Schlussfolgerung"],hint:"The area someone is responsible for. Their jurisdiction or domain of authority.",sSrc:"That does not fall within my area of responsibility."}
]},
{id:"deu_r29l7",title:"Auf dem Pr\u00fcfstand",icon:"\ud83d\udccb",xp:15,board:true,steps:[
{type:"intro",title:"Auf dem Pr\u00fcfstand",desc:"Everything from Unit 29 on the test bench. Prove you can argue, concede, compare, and conclude. In formal German.",goals:["Test all three grammar constructs in combination","Master political German and debate vocabulary","Use discourse markers precisely"]},
{type:"teach",trg:"der Minister",src:"minister (government)",pos:"noun",gender:"m",note:"From Latin 'minister' (servant). 'Bundesminister' for federal,\n'Landesminister' for state level.",example:"A: Wer ist der neue Minister?\nB: Der Minister für Bildung.\nA: Was hat der Minister gesagt?\nB: Er unterstuetzt die Reform.",exampleSrc:"A: Who is the new minister?\nB: The minister for education.\nA: What did the minister say?\nB: He supports the reform.",funFact:"Did you know the Latin root 'minister' means servant? Ironic for one of the most powerful offices. In Germany, the Kanzler appoints ministers: 'Bundesminister' for federal, 'Landesminister' for state level."},
{type:"teach",trg:"die Ministerin",src:"minister (female)",pos:"noun",gender:"f",note:"Minister + -in. 'Frau Ministerin' is the formal address.\nMultiple women have held top ministries in Germany.",example:"A: Die Ministerin hält eine Rede.\nB: Welche Ministerin?\nA: Die Justizministerin.\nB: Sie ist sehr überzeugend.",exampleSrc:"A: The minister is giving a speech.\nB: Which minister?\nA: The justice minister.\nB: She is very convincing.",funFact:"Minister + -in. Die Ministerin. 'Frau Ministerin' is the formal address. Multiple women have held top ministries: defense, justice, education. The -in suffix on Latin-origin words is standard German."},
{type:"mc",q:"Wer f\u00fchrt die deutsche Regierung und bestimmt die Richtlinien der Politik?",opts:["Der Kanzler oder die Kanzlerin","Der Bundespr\u00e4sident","Der Bundestagspr\u00e4sident","Der Ministerpr\u00e4sident"],ans:"Der Kanzler oder die Kanzlerin",hint:"The head of government (not head of state) who has Richtlinienkompetenz. From Latin 'cancellarius.'"},
{type:"teach",trg:"die Petition",src:"petition",pos:"noun",gender:"f",note:"From Latin 'petitio' (request). Germany's Bundestag has a\ndedicated Petitionsausschuss. Over 10,000 petitions per year.",example:"A: Haben Sie die Petition unterschrieben?\nB: Ja, für bessere Bildung.\nA: Wie viele Unterschriften hat die Petition?\nB: Über 50.000.",exampleSrc:"A: Did you sign the petition?\nB: Yes, for better education.\nA: How many signatures does the petition have?\nB: Over 50,000.",funFact:"Germany's Bundestag has a dedicated Petitionsausschuss (petitions committee) where citizens can petition directly. The word comes from Latin 'petitio' (request), a right that dates back centuries."},
{type:"teach",trg:"das Plenum",src:"plenary session, full assembly",pos:"noun",gender:"n",note:"From Latin 'plenum' (full assembly). The Ausschuss does\nthe detailed work. The Plenum makes the final decision.",example:"A: Wann wird im Plenum abgestimmt?\nB: Morgen Nachmittag.\nA: Sind alle Abgeordneten im Plenum?\nB: Bei wichtigen Abstimmungen ja.",exampleSrc:"A: When will the plenary vote?\nB: Tomorrow afternoon.\nA: Are all MPs in the plenary?\nB: For important votes, yes.",funFact:"While Aussch\u00fcsse do the detailed work, the Plenum decides. 'Im Plenum abstimmen' (to vote in plenary session) means all parliamentarians are present. Latin 'plenum' means full, and that is the point: everyone votes."},
{type:"fb",s:"Im {1} wird \u00fcber den Gesetzentwurf abgestimmt, wenn alle Abgeordneten anwesend sind.",a:["Plenum"],opts:["Ausschuss","Plenum","Wahlkampf","Ministerium"],hint:"The full assembly of all parliamentarians, from Latin for 'full.' The final decision is made here, not in committee.",sSrc:"The plenary session votes on the bill when all members are present."},
{type:"teach",trg:"die Strategie",src:"strategy",pos:"noun",gender:"f",note:"From Greek 'strategia' (generalship). The long-term plan\nbehind short-term actions.",example:"A: Was ist die Strategie der Regierung?\nB: Mehr Dialog und weniger Konfrontation.\nA: Ist das eine gute Strategie?\nB: Sie hat bisher funktioniert.",exampleSrc:"A: What is the government's strategy?\nB: More dialogue and less confrontation.\nA: Is that a good strategy?\nB: It has worked so far.",funFact:"In politics, Strategie is the long-term plan behind short-term actions. 'Eine politische Strategie entwickeln' (to develop a political strategy). The Greek root 'strategia' meant generalship, the art of winning wars."},
{type:"teach",trg:"der Vertreter",src:"representative",pos:"noun",gender:"m",note:"From 'vertreten' (to represent). 'Volksvertreter' = Abgeordnete.\nOne who steps in for others.",example:"A: Wer ist Ihr Vertreter im Parlament?\nB: Der Abgeordnete aus meinem Wahlkreis.\nA: Ist er ein guter Vertreter?\nB: Er vertritt unsere Interessen gut.",exampleSrc:"A: Who is your representative in parliament?\nB: The MP from my constituency.\nA: Is he a good representative?\nB: He represents our interests well.",funFact:"A Volksvertreter (people's representative) is the same as an Abgeordnete. The word 'Vertreter' literally means one who steps in for others, from 'vertreten' (to step in someone's place)."},
{type:"teach",trg:"die Vertreterin",src:"representative (female)",pos:"noun",gender:"f",note:"Vertreter + -in. Standard gender pair in political language.\n'Die Vertreterin der Opposition sprach zuerst.'",example:"A: Die Vertreterin der Opposition sprach zuerst.\nB: Was hat sie gesagt?\nA: Sie fordert mehr Transparenz.\nB: Eine berechtigte Forderung.",exampleSrc:"A: The opposition representative spoke first.\nB: What did she say?\nA: She demands more transparency.\nB: A legitimate demand.",funFact:"Vertreter + -in. Die Vertreterin. A female representative. 'Die Vertreterin der Opposition sprach zuerst.' Standard gender pair in political language."},
{type:"teach",trg:"reformorientiert",src:"reform-oriented",pos:"adj",gender:null,note:"Reform + orientiert (oriented). Neither radical nor conservative:\nstrategically progressive.",example:"A: Ist die Partei reformorientiert?\nB: Ja, sie will vieles ändern.\nA: Reformorientierte Politik ist wichtig.\nB: Besonders in der Bildung.",exampleSrc:"A: Is the party reform-oriented?\nB: Yes, they want to change a lot.\nA: Reform-oriented policy is important.\nB: Especially in education.",funFact:"Reform + orientiert (oriented). Reform-oriented. 'Eine reformorientierte Politik.' The adjective for those who push for change. Neither radical nor conservative: strategically progressive."},
{type:"teach",trg:"verfassungsm\u00e4\u00dfig",src:"constitutional",pos:"adj",gender:null,note:"Verfassung (constitution) + maessig (in accordance with).\nThe adjectival form of legal conformity with the Grundgesetz.",example:"A: Ist das verfassungsm\u00e4\u00dfig?\nB: Ja, das Bundesverfassungsgericht hat entschieden.\nA: Verfassungsm\u00e4\u00dfig garantierte Rechte...\nB: ...dürfen nicht angetastet werden.",exampleSrc:"A: Is that constitutional?\nB: Yes, the Federal Constitutional Court has decided.\nA: Constitutionally guaranteed rights...\nB: ...may not be touched.",funFact:"Verfassung (constitution) + maessig (in accordance with). Constitutional. 'Verfassungsmaessig garantierte Rechte.' The adjectival form of legal conformity with the Grundgesetz."},
{type:"mc",q:"Ist die Entscheidung verfassungsm\u00e4\u00dfig? Wer entscheidet das in Deutschland?",opts:["Der Bundestag allein","Der Kanzler pers\u00f6nlich","Das Bundesverfassungsgericht","Die Opposition im Parlament"],ans:"Das Bundesverfassungsgericht",hint:"The institution that rules on whether laws and decisions comply with the Grundgesetz. Germany's highest court for constitutional matters."},
{type:"mc",q:"Die Partei verfolgt eine {blank} Strategie für das Bildungssystem.",opts:["reformorientierte","verfassungsmaessige","oppositionelle","anfechtbare"],ans:"reformorientierte",hint:"Pushing for change in a strategic, progressive way. Neither radical nor conservative."}
]},
{id:"deu_r29l7b",title:"Auf dem Pr\u00fcfstand (Teil 2)",icon:"\ud83d\udccb",xp:15,board:true,steps:[
{type:"intro",title:"Auf dem Pr\u00fcfstand (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"populistisch",src:"populist",pos:"adj",gender:null,note:"From Latin 'populus' (people). In German political discourse,\nalmost always negative: oversimplifying for political gain.",example:"A: War die Rede populistisch?\nB: Ja, sie hat Aengste geschuert.\nA: Populistische Rhetorik ist gefaehrlich.\nB: Weil sie komplexe Themen vereinfacht.",exampleSrc:"A: Was the speech populist?\nB: Yes, it stirred up fears.\nA: Populist rhetoric is dangerous.\nB: Because it oversimplifies complex topics.",funFact:"'Populistisch' is almost always negative in German political discourse: oversimplifying complex issues for political gain. Not the same as 'popul\u00e4r' (popular). Latin 'populus' (people) sounds noble, but the modern usage is not."},
{type:"teach",trg:"radikal",src:"radical",pos:"adj",gender:null,note:"From Latin 'radix' (root). In German politics, means going\nto the extreme. The Verfassungsschutz monitors it.",example:"A: Sind die Forderungen radikal?\nB: Einige ja, andere nicht.\nA: Radikale Positionen schaden der Debatte.\nB: Sie machen Kompromisse unmöglich.",exampleSrc:"A: Are the demands radical?\nB: Some are, others are not.\nA: Radical positions harm the debate.\nB: They make compromises impossible.",funFact:"The Verfassungsschutz (domestic intelligence) monitors 'radikale Bestrebungen' (radical efforts). In German political language, radikal means going to the extreme. Interestingly, the Latin root 'radix' just means root."},
{type:"teach",trg:"strittig",src:"disputed, contentious",pos:"adj",gender:null,note:"From 'Streit' (dispute). Lighter than 'umstritten.'\nSomething strittig is debated, not fought over.",example:"A: Ist der Punkt strittig?\nB: Ja, darüber gibt es verschiedene Meinungen.\nA: Das Thema bleibt strittig.\nB: Vielleicht klaert die nächsste Debatte es.",exampleSrc:"A: Is the point contentious?\nB: Yes, there are different opinions about it.\nA: The topic remains disputed.\nB: Perhaps the next debate will clarify it.",funFact:"Lighter than 'umstritten,' something strittig is merely debated, while something umstritten faces active opposition. 'Ein strittiger Punkt' (a contentious point). Built on 'Streit' (dispute)."},
{type:"teach",trg:"unanfechtbar",src:"uncontestable, irrefutable",pos:"adj",gender:null,note:"Un- (not) + anfechtbar (challengeable). What cannot be\nlegally challenged. Final, done, beyond dispute.",example:"A: Ist die Entscheidung unanfechtbar?\nB: Ja, sie kann nicht mehr angefochten werden.\nA: Ein unanfechtbares Recht.\nB: Das Grundgesetz schützt es.",exampleSrc:"A: Is the decision uncontestable?\nB: Yes, it can no longer be challenged.\nA: An incontestable right.\nB: The Basic Law protects it.",funFact:"Un- (not) + anfechtbar (challengeable). Uncontestable, irrefutable. 'Ein unanfechtbares Recht.' What cannot be legally challenged. The ultimate legal adjective: final, done, beyond dispute."},
{type:"teach",trg:"undemokratisch",src:"undemocratic",pos:"adj",gender:null,note:"Un- + demokratisch. One of the strongest political\naccusations in Germany.",example:"A: War die Entscheidung undemokratisch?\nB: Das werfen die Kritiker vor.\nA: Undemokratisches Verhalten wird nicht toleriert.\nB: Die Verfassung schützt davor.",exampleSrc:"A: Was the decision undemocratic?\nB: That is what the critics allege.\nA: Undemocratic behavior is not tolerated.\nB: The constitution protects against it.",funFact:"Un- + demokratisch. Undemocratic. 'Eine undemokratische Entscheidung.' In Germany, calling something 'undemokratisch' is one of the strongest political accusations."},
{type:"match",pairs:[{trg:"radikal",src:"radical"},{trg:"strittig",src:"disputed, contentious"},{trg:"unanfechtbar",src:"uncontestable, irrefutable"},{trg:"undemokratisch",src:"undemocratic"}]},
{type:"teach",trg:"konservativ",src:"conservative",pos:"adj",gender:null,note:"From Latin 'conservare' (to preserve). In Germany, CDU/CSU.\nMore centrist than American conservatism.",example:"A: Ist die CDU konservativ?\nB: Ja, aber im deutschen Sinne.\nA: Was bedeutet konservativ hier?\nB: Traditionen bewahren, aber nicht radikal.",exampleSrc:"A: Is the CDU conservative?\nB: Yes, but in the German sense.\nA: What does conservative mean here?\nB: Preserving traditions, but not radical.",funFact:"In Germany, the CDU/CSU is the main konservative party, but more centrist than American conservatism by international standards. Latin 'conservare' (to preserve) captures the core idea: holding on to what works."},
{type:"teach",trg:"liberal",src:"liberal (pro-free-market)",pos:"adj",gender:null,note:"From Latin 'liberalis' (of freedom). In Germany means\npro-free-market (FDP). Different from American usage.",example:"A: Was bedeutet liberal in Deutschland?\nB: Pro Marktwirtschaft und individuelle Freiheit.\nA: Also die FDP?\nB: Ja, die FDP ist die liberale Partei.",exampleSrc:"A: What does liberal mean in Germany?\nB: Pro free market and individual freedom.\nA: So the FDP?\nB: Yes, the FDP is the liberal party.",funFact:"Watch out: in Germany, 'liberal' means pro-free-market (FDP), not left-leaning as in American English. A classic false friend across the Atlantic. Latin 'liberalis' (of freedom) is the shared root."},
{type:"teach",trg:"progressiv",src:"progressive",pos:"adj",gender:null,note:"From Latin 'progressus' (advancement). Forward-moving.\nTo the left of liberal, not as far as radikal.",example:"A: Ist die Partei progressiv?\nB: Ja, sie will gesellschaftlichen Wandel.\nA: Progressive Politik bedeutet Fortschritt?\nB: Ja, aber mit Verantwortung.",exampleSrc:"A: Is the party progressive?\nB: Yes, they want social change.\nA: Progressive politics means progress?\nB: Yes, but with responsibility.",funFact:"On the German political spectrum, progressiv sits to the left of liberal but not as far as radikal. Forward-moving and reform-oriented. Latin 'progressus' (advancement) captures the direction: always forward."},
{type:"teach",trg:"reaktion\u00e4r",src:"reactionary",pos:"adj",gender:null,note:"From French 'reactionnaire.' Wanting to go back to an earlier\nstate. Strongly negative in political discourse.",example:"A: Ist das eine reaktion\u00e4re Position?\nB: Ja, sie will zurück in die Vergangenheit.\nA: Reaktion\u00e4re Tendenzen sind problematisch.\nB: Sie blockieren den Fortschritt.",exampleSrc:"A: Is that a reactionary position?\nB: Yes, it wants to go back to the past.\nA: Reactionary tendencies are problematic.\nB: They block progress.",funFact:"The polar opposite of progressiv: wanting to go back to an earlier state. 'Reaktion\u00e4re Tendenzen' is strongly negative in political discourse. Borrowed from French 'r\u00e9actionnaire,' it implies resistance to all change."},
{type:"fb",s:"Ist das ein radikaler oder ein {1} Vorschlag? Er will Ver\u00e4nderung, aber gemessen.",a:["progressiv"],opts:["reaktion\u00e4r","konservativ","populistisch","progressiv"],hint:"The adjective from Latin 'progressus' (advancement). Forward-moving reform, but not as extreme as radical.",sSrc:"Is that a radical or a progressive proposal? He wants change, but measured."},
{type:"teach",trg:"durchsetzen",src:"to push through, to enforce",pos:"verb",gender:null,note:"Durch (through) + setzen (to set). Separable. Reflexive:\n'sich durchsetzen' means to prevail.",example:"A: Kann die Regierung die Reform durchsetzen?\nB: Nur mit einer Mehrheit.\nA: Er hat sich durchgesetzt.\nB: Ja, sein Argument war überzeugend.",exampleSrc:"A: Can the government push through the reform?\nB: Only with a majority.\nA: He prevailed.\nB: Yes, his argument was convincing.",funFact:"Durch (through) + setzen (to set). To push through, to enforce. 'Eine Reform durchsetzen.' Separable. Reflexive: 'sich durchsetzen' means to prevail. You set something through all obstacles."},
{type:"teach",trg:"entgegenwirken",src:"to counteract",pos:"verb",gender:null,note:"Entgegen (against) + wirken (to work/have effect).\nNot separable. The constructive response to a negative force.",example:"A: Wie kann man dem Populismus entgegenwirken?\nB: Mit Bildung und Dialog.\nA: Entgegenwirken statt ignorieren?\nB: Ja, aktives Handeln ist wichtig.",exampleSrc:"A: How can one counteract populism?\nB: With education and dialogue.\nA: Counteract instead of ignore?\nB: Yes, active action is important.",funFact:"Entgegen (against) + wirken (to work/have effect). To counteract. 'Dem Populismus entgegenwirken.' Not separable. You work against something. The constructive response to a negative force."},
{type:"mc",q:"'Hätten sowohl die Regierung als auch die Opposition Kompromissbereitschaft gezeigt, wäre das Gesetz verabschiedet worden, obgleich es umstritten war.' Wie viele fortgeschrittene Konstrukte?",opts:["Drei: Verb-Erst-Konditionalsatz + Konnektorenpaar + Konzessivsatz","Zwei: nur Konditionalsatz und Konzessiv","Eins: nur der Konditionalsatz","Vier: inklusive einer vollständigen Passivkonstruktion innerhalb des Satzes"],ans:"Drei: Verb-Erst-Konditionalsatz + Konnektorenpaar + Konzessivsatz",hint:"Count the number of distinct advanced grammatical structures. Look at: the unusual first-position placement, how both subject elements are connected, and how the final clause relates."},
{type:"fb",s:"Die Entscheidung betrifft {1} Bürger als auch Politiker gleichermassen.",a:["sowohl"],opts:["weder","sowohl","nicht","zwar"],hint:"The first bracket of the inclusion pair. Both citizens AND ALSO politicians.",sSrc:"The decision affects both citizens and politicians equally."},
{type:"mc",q:"Welche Wortstellung ist nach 'obgleich' korrekt?",opts:["'obgleich war die Debatte hitzig' (Verb an zweiter Stelle)","'obgleich die Debatte war hitzig' (Verb in der Mitte)","'obgleich die Debatte hitzig war' (Verb am Ende)","'die Debatte war hitzig, obgleich' (Verb vor obgleich)"],ans:"'obgleich die Debatte hitzig war' (Verb am Ende)",hint:"This conjunction belongs to the subordinating class that pushes the finite action word to the final position. Check each option for correct placement."},
{type:"drag_fill",s:"{1} man die Minderheit ignoriert, {2} die Demokratie Schaden.",blanks:{"1":"W\u00fcrde","2":"n\u00e4hme"},pool:["W\u00fcrde","n\u00e4hme","Wird","nimmt","H\u00e4tte","genommen"],hint:"Verb-first conditional without 'wenn'. Both verbs in Konjunktiv II. If one were to ignore... would suffer harm."},
{type:"match",pairs:[{trg:"konservativ",src:"preserving tradition"},{trg:"liberal",src:"pro-freedom/free-market"},{trg:"progressiv",src:"forward-moving reform"},{trg:"reaktion\u00e4r",src:"wanting to go back"}]},
{type:"mc",q:"Was bedeutet 'strittig'?",opts:["disputed, contentious","constitutional","populist","progressive"],ans:"disputed, contentious",hint:"From Streit (dispute/quarrel). An adjective meaning subject to argument."},
{type:"fb",s:"Ist die Entscheidung {1}?",a:["unanfechtbar"],opts:["der Minister","die Vertreterin","die Ministerin","unanfechtbar"],hint:"un- + anfechten (to contest) + -bar (able). Cannot be legally challenged.",sSrc:"Is the decision uncontestable?"},
{type:"mc",q:"Was bedeutet 'undemokratisch'?",opts:["disputed, contentious","strategy","to counteract","undemocratic"],ans:"undemocratic",hint:"un- prefix negates demokratisch. Against the principles of democratic governance."},
{type:"fb",s:"Kann die Regierung die Reform {1}?",a:["durchsetzen"],opts:["durchsetzen","verfassungsm\\u00e4\\u00dfig","entgegenwirken","der Minister"],hint:"durch (through) + setzen (to set). To push something through despite resistance.",sSrc:"Can the government push through the reform?"},
{type:"mc",q:"Was bedeutet 'entgegenwirken'?",opts:["petition","to counteract","minister (female)","constitutional"],ans:"to counteract",hint:"entgegen (against) + wirken (to work/have effect). To work against something."}
]},
{id:"deu_r29l8",title:"Wichtiger Beitrag",icon:"\ud83c\udfc6",xp:15,board:true,steps:[
{type:"intro",title:"Wichtiger Beitrag",desc:"The debate is over. Yilmaz says two words. Learn the formal debate phrases that complete your argumentation toolkit. The capstone of Unit 29.",goals:["Master formal debate phrases","Review all constructs from Unit 29","Celebrate the milestone of public German discourse"]},
{type:"teach",trg:"Ich bin der Auffassung, dass",src:"I am of the view that",pos:"adv",gender:null,note:"The formal position statement. Stronger than 'Ich denke.'\nAcademic and legal standard.",example:"A: Was ist Ihre Meinung?\nB: Ich bin der Auffassung, dass wir handeln müssen.\nA: Und warum?\nB: Weil die Zeit draengt.",exampleSrc:"A: What is your opinion?\nB: I am of the view that we must act.\nA: And why?\nB: Because time is pressing.",funFact:"'I am of the view that.' The formal position statement. Stronger than 'Ich denke' or 'Ich glaube.' You have an Auffassung (understanding/view), not just an opinion. Academic and legal standard."},
{type:"teach",trg:"Meiner Ansicht nach",src:"in my view",pos:"adv",gender:null,note:"Ansicht from 'ansehen' (to look at). Dative case: meiner.\nThe polite but firm positioning phrase.",example:"A: Meiner Ansicht nach brauchen wir Reform.\nB: Das sehe ich auch so.\nA: Meiner Ansicht nach ist der Kompromiss fair.\nB: Darauf können wir aufbauen.",exampleSrc:"A: In my view, we need reform.\nB: I see it that way too.\nA: In my view, the compromise is fair.\nB: We can build on that.",funFact:"'In my view.' 'Ansicht' from 'ansehen' (to look at). Your view of the matter. 'Meiner Ansicht nach brauchen wir Reform.' Dative case: meiner. The polite but firm positioning phrase."},
{type:"teach",trg:"Es steht au\u00dfer Frage, dass",src:"it is beyond question that",pos:"adv",gender:null,note:"The phrase that closes debate on a point.\nEstablishes something as uncontested fact.",example:"A: Ist das sicher?\nB: Es steht au\u00dfer Frage, dass die Grundrechte gelten.\nA: Es steht au\u00dfer Frage, dass wir handeln müssen.\nB: Darin sind wir uns einig.",exampleSrc:"A: Is that certain?\nB: It is beyond question that fundamental rights apply.\nA: It is beyond question that we must act.\nB: On that we agree.",funFact:"'It is beyond question that.' The phrase that closes debate on a point. 'Es steht ausser Frage, dass die Grundrechte gelten.' When you want to establish something as uncontested fact."},
{type:"teach",trg:"Dem ist entgegenzuhalten, dass",src:"to counter that, it must be said that",pos:"adv",gender:null,note:"Dem (dative) + entgegenzuhalten (to hold against).\nElegant, indirect, devastating. The formal objection.",example:"A: Das Argument scheint stark.\nB: Dem ist entgegenzuhalten, dass die Daten veraltet sind.\nA: Ein guter Einwand.\nB: Fakten müssen aktuell sein.",exampleSrc:"A: The argument seems strong.\nB: To counter that, the data is outdated.\nA: A good objection.\nB: Facts must be current.",funFact:"'To counter that, it must be said that.' Dem (dative) + entgegenzuhalten (to hold against). Elegant, indirect, devastating. You do not attack. You present what must be held against the argument."},
{type:"teach",trg:"Es l\u00e4sst sich nicht leugnen, dass",src:"it cannot be denied that",pos:"adv",gender:null,note:"Leugnen (to deny). The concession marker that acknowledges\ninconvenient truth. Honest, then move on.",example:"A: Gibt es Probleme?\nB: Es l\u00e4sst sich nicht leugnen, dass es welche gibt.\nA: Aber es gibt auch Fortschritte.\nB: Auch das lässt sich nicht leugnen.",exampleSrc:"A: Are there problems?\nB: It cannot be denied that there are some.\nA: But there is also progress.\nB: That cannot be denied either.",funFact:"'It cannot be denied that.' 'Leugnen' (to deny). The concession marker that acknowledges inconvenient truth. Honest, then move on."},
{type:"match",pairs:[{trg:"Meiner Ansicht nach",src:"in my view"},{trg:"Es steht au\u00dfer Frage, dass",src:"it is beyond question that"},{trg:"Dem ist entgegenzuhalten, dass",src:"to counter that, it must be said that"},{trg:"Es l\u00e4sst sich nicht leugnen, dass",src:"it cannot be denied that"}]},
{type:"teach",trg:"Daraus ergibt sich",src:"from that follows",pos:"adv",gender:null,note:"'Sich ergeben' (to result). The logical consequence phrase.\nThe evidence produces the conclusion organically.",example:"A: Die Mehrheit hat entschieden.\nB: Daraus ergibt sich die Notwendigkeit zu handeln.\nA: Daraus ergibt sich auch Verantwortung.\nB: Für alle Beteiligten.",exampleSrc:"A: The majority has decided.\nB: From that follows the necessity to act.\nA: From that also follows responsibility.\nB: For all involved.",funFact:"'From that follows.' 'Sich ergeben' (to result). The logical consequence phrase. 'Daraus ergibt sich die Notwendigkeit zu handeln.' The evidence produces the conclusion organically."},
{type:"teach",trg:"Auf den Punkt gebracht",src:"in a nutshell, to sum up",pos:"adv",gender:null,note:"Brought to the point. The summary marker.\nEverything condensed to its essence.",example:"A: Wie würden Sie es zusammenfassen?\nB: Auf den Punkt gebracht: Wir brauchen Dialog.\nA: Auf den Punkt gebracht: mehr Kompromissbereitschaft.\nB: Genau.",exampleSrc:"A: How would you summarize it?\nB: In a nutshell: we need dialogue.\nA: To sum up: more willingness to compromise.\nB: Exactly.",funFact:"'Brought to the point.' The summary marker. 'Auf den Punkt gebracht: Wir brauchen Dialog.' Everything condensed to its essence. The German 'in a nutshell.'"},
{type:"teach",trg:"Alles in allem",src:"all in all",pos:"adv",gender:null,note:"The comprehensive summary. Everything considered,\neverything weighed. The final assessment.",example:"A: Wie war die Debatte?\nB: Alles in allem sehr produktiv.\nA: Alles in allem ein Erfolg?\nB: Ja, trotz einiger Meinungsverschiedenheiten.",exampleSrc:"A: How was the debate?\nB: All in all, very productive.\nA: All in all a success?\nB: Yes, despite some disagreements.",funFact:"'All in all.' 'Alles in allem war es eine produktive Debatte.' The comprehensive summary. Everything considered, everything weighed. The final assessment."},
{type:"teach",trg:"angesichts",src:"in the face of, in view of",pos:"prep",gender:null,note:"An (at) + Gesichts (face). Takes genitive.\nYou look the situation in the face.",example:"A: Angesichts der Herausforderungen...\nB: ...müssen wir zusammenarbeiten.\nA: Angesichts der Lage?\nB: Ist schnelles Handeln noetig.",exampleSrc:"A: In the face of the challenges...\nB: ...we must work together.\nA: In view of the situation?\nB: Quick action is necessary.",funFact:"An (at) + Gesichts (face). In the face of, in view of. Takes genitive: 'Angesichts der Herausforderungen.' You look the situation in the face. Formal written register."},
{type:"teach",trg:"aufgrund",src:"on the basis of, due to",pos:"prep",gender:null,note:"Auf (on) + Grund (ground/reason). Takes genitive.\nStanding on the ground of evidence.",example:"A: Warum wurde es abgelehnt?\nB: Aufgrund der Bedenken.\nA: Aufgrund der Ergebnisse...\nB: ...müssen wir die Strategie ändern.",exampleSrc:"A: Why was it rejected?\nB: Due to the concerns.\nA: On the basis of the results...\nB: ...we must change the strategy.",funFact:"Auf (on) + Grund (ground/reason). On the basis of, due to. Takes genitive: 'Aufgrund der Ergebnisse.' Standing on the ground of evidence. Can be written 'auf Grund' (two words)."},
{type:"match",pairs:[{trg:"Auf den Punkt gebracht",src:"in a nutshell, to sum up"},{trg:"Alles in allem",src:"all in all"},{trg:"angesichts",src:"in the face of, in view of"},{trg:"aufgrund",src:"on the basis of, due to"}]},
{type:"fb",s:"{1} der Ergebnisse müssen wir die Strategie ändern.",a:["Aufgrund"],opts:["Aufgrund","Angesichts","Trotzdem","Folglich"],hint:"A preposition meaning 'due to' or 'on the basis of.' Takes genitive. Built from Auf + Grund.",sSrc:"Due to the results, we must change the strategy."}
]},
{id:"deu_r29l8b",title:"Wichtiger Beitrag (Teil 2)",icon:"\ud83c\udfc6",xp:15,board:true,steps:[
{type:"intro",title:"Wichtiger Beitrag (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"ungeachtet",src:"regardless of, irrespective of",pos:"prep",gender:null,note:"Un- + geachtet (regarded). Takes genitive.\nYou have regarded and you disregard anyway.",example:"A: Gibt es Widerstand?\nB: Ungeachtet der Kritik geht es weiter.\nA: Ungeachtet der Kosten?\nB: Ja, die Sache ist wichtiger.",exampleSrc:"A: Is there resistance?\nB: Regardless of the criticism, it continues.\nA: Regardless of the costs?\nB: Yes, the cause is more important.",funFact:"Un- + geachtet (regarded). Regardless of, irrespective of. Takes genitive: 'Ungeachtet der Bedenken.' You have regarded the concerns, and you disregard them anyway. Formal, decisive."},
{type:"teach",trg:"zugunsten",src:"in favor of",pos:"prep",gender:null,note:"Zu (to) + Gunsten (favor). Takes genitive.\nOn whose side the decision falls.",example:"A: Wer profitiert?\nB: Zugunsten der Minderheit.\nA: Die Entscheidung fiel zugunsten der Klaeger.\nB: Ein wichtiges Signal.",exampleSrc:"A: Who benefits?\nB: In favor of the minority.\nA: The decision was made in favor of the plaintiffs.\nB: An important signal.",funFact:"Zu (to) + Gunsten (favor). In favor of. Takes genitive: 'Zugunsten der Minderheit.' The preposition of benefit. On whose side the decision falls."},
{type:"teach",trg:"polarisieren",src:"to polarize",pos:"verb",gender:null,note:"From Greek 'polos' (axis/pole). Pulling people to\nopposite poles. Seen as dangerous in German politics.",example:"A: Die Debatte polarisiert.\nB: Ja, es gibt kaum noch Mitte.\nA: Polarisieren schadet der Demokratie.\nB: Deshalb brauchen wir mehr Dialog.",exampleSrc:"A: The debate polarizes.\nB: Yes, there is hardly any center left.\nA: Polarizing harms democracy.\nB: That is why we need more dialogue.",funFact:"'Die Debatte polarisiert' means pulling people to opposite poles, and in German politics, Polarisierung is seen as dangerous to the democratic center. The Greek root 'polos' (axis) gives the image of two extremes."},
{type:"teach",trg:"relativieren",src:"to put into perspective, to relativize",pos:"verb",gender:null,note:"From Latin 'relativus.' Making something relative,\nreducing its absolute weight. Can be positive or negative.",example:"A: Sollte man das Ergebnis relativieren?\nB: Nein, die Zahlen sprechen für sich.\nA: Kritiker relativieren die Erfolge.\nB: Das ist unfair.",exampleSrc:"A: Should one put the result into perspective?\nB: No, the numbers speak for themselves.\nA: Critics relativize the successes.\nB: That is unfair.",funFact:"'Man sollte das Ergebnis nicht relativieren' means: do not downplay the result. Relativieren reduces the absolute weight of something, which can be positive (adding nuance) or negative (dismissing). Latin 'relativus' is the source."},
{type:"teach",trg:"zur\u00fcckweisen",src:"to reject, to dismiss",pos:"verb",gender:null,note:"Zurück (back) + weisen (to direct). Separable.\nStronger than ablehnen. You direct it back.",example:"A: Der Vorwurf wurde zurückgewiesen.\nB: Zu Recht?\nA: Ja, er war unbegr\u00fcndet.\nB: Dann war die Zurückweisung richtig.",exampleSrc:"A: The accusation was rejected.\nB: Rightly so?\nA: Yes, it was unfounded.\nB: Then the rejection was correct.",funFact:"Zurück (back) + weisen (to direct). To reject, to dismiss. 'Den Vorwurf zurückweisen.' Separable. You direct it back where it came from. Stronger than ablehnen."},
{type:"match",pairs:[{trg:"zugunsten",src:"in favor of"},{trg:"polarisieren",src:"to polarize"},{trg:"relativieren",src:"to put into perspective, to relativize"},{trg:"zur\u00fcckweisen",src:"to reject, to dismiss"}]},
{type:"teach",trg:"infrage stellen",src:"to call into question, to challenge",pos:"verb",gender:null,note:"In + Frage (question) + stellen (to place). Not rejecting,\nbut questioning the validity.",example:"A: Kann man die Entscheidung infrage stellen?\nB: Ja, jeder hat das Recht dazu.\nA: Er stellt die Methode infrage.\nB: Eine berechtigte Kritik.",exampleSrc:"A: Can one call the decision into question?\nB: Yes, everyone has the right to.\nA: He challenges the method.\nB: A legitimate criticism.",funFact:"In + Frage (question) + stellen (to place). To call into question, to challenge. 'Die Entscheidung infrage stellen.' You place something inside a question mark. Not rejecting, but questioning its validity."},
{type:"teach",trg:"beipflichten",src:"to agree with, to concur",pos:"verb",gender:null,note:"Bei (by/with) + pflichten (duty/to agree). Formal agreement.\nOld-fashioned but still used in formal debate.",example:"A: Stimmen Sie zu?\nB: Ich pflichte Ihnen voll und ganz bei.\nA: Darf ich Ihnen beipflichten?\nB: Selbstverständlich.",exampleSrc:"A: Do you agree?\nB: I fully and completely concur.\nA: May I agree with you?\nB: Of course.",funFact:"Bei (by/with) + pflichten (duty/to agree). To agree with, to concur. 'Ich pflichte Ihnen bei.' Formal agreement. You place your obligation alongside theirs. Old-fashioned but still used in formal debate."},
{type:"teach",trg:"entsch\u00e4rfen",src:"to defuse, to de-escalate",pos:"verb",gender:null,note:"Ent- (un-) + schaerfen (to sharpen). Literally: to un-sharpen.\nRemoving the edge from a conflict.",example:"A: Die Situation ist angespannt.\nB: Wir müssen sie entsch\u00e4rfen.\nA: Wie kann man den Konflikt entsch\u00e4rfen?\nB: Durch Dialog und Zugeständnisse.",exampleSrc:"A: The situation is tense.\nB: We must defuse it.\nA: How can one de-escalate the conflict?\nB: Through dialogue and concessions.",funFact:"Ent- (un-) + schaerfen (to sharpen). To defuse, to de-escalate. 'Die Situation entschaerfen.' Literally: to un-sharpen. Removing the edge from a conflict."},
{type:"teach",trg:"provozieren",src:"to provoke",pos:"verb",gender:null,note:"From Latin 'provocare' (to call forth). In debates,\nProvokation can be strategic or destructive.",example:"A: Wollte der Redner provozieren?\nB: Ja, er wollte eine Reaktion.\nA: Provozieren ist keine Strategie.\nB: Manchmal leider doch.",exampleSrc:"A: Did the speaker want to provoke?\nB: Yes, he wanted a reaction.\nA: Provoking is not a strategy.\nB: Unfortunately, sometimes it is.",funFact:"Provokation in debates can be strategic or destructive. 'Der Redner wollte provozieren' means the speaker wanted to stir things up. Latin 'provocare' literally means to call forth something hidden."},
{type:"teach",trg:"anfechtbar",src:"contestable, challengeable",pos:"adj",gender:null,note:"Anfechten (to challenge) + -bar (able). The opposite of\nunanfechtbar. It can be challenged.",example:"A: Ist das Urteil anfechtbar?\nB: Ja, man kann Berufung einlegen.\nA: Eine anfechtbare Entscheidung.\nB: Die nächsste Instanz wird entscheiden.",exampleSrc:"A: Is the verdict contestable?\nB: Yes, one can appeal.\nA: A contestable decision.\nB: The next instance will decide.",funFact:"Anfechten (to challenge) + -bar (able). Contestable, challengeable. The opposite of unanfechtbar. 'Das Urteil ist anfechtbar.' It can be challenged in a higher court. Legal precision."},
{type:"match",pairs:[{trg:"beipflichten",src:"to agree with, to concur"},{trg:"entsch\u00e4rfen",src:"to defuse, to de-escalate"},{trg:"provozieren",src:"to provoke"},{trg:"anfechtbar",src:"contestable, challengeable"}]},
{type:"mc",q:"Ein Podiumsteilnehmer schliesst: 'Unter dem Strich war diese Debatte ein Erfolg.' Was bedeutet 'unter dem Strich'?",opts:["Unter großem Druck zustande gekommen","Unter der Oberfläche verborgen","Trotz allem Widerstand","Alles in allem, die Bilanz"],ans:"Alles in allem, die Bilanz",hint:"From accounting: the final number below the calculation line. What counts when everything is added up."},
{type:"fb",s:"{1} der aktuellen Herausforderungen müssen wir handeln.",a:["Angesichts"],opts:["Angesichts","Trotzdem","Obgleich","Allerdings"],hint:"A formal genitive preposition. You face a situation directly and act on what you see before you.",sSrc:"In the face of the current challenges, we must act."},
{type:"mc",q:"'Hätte man sowohl die Bedenken der Minderheit als auch die Forderungen der Mehrheit beachtet, wäre ein Kompromiss möglich gewesen, obgleich die Positionen weit auseinanderlagen.' Dieser Satz kombiniert...",opts:["Nur einen Konditionalsatz und einen Konzessiv","Nur Konnektorenpaare ohne Bedingungsstruktur","Verb-Erst-Konditionalsatz + sowohl...als auch + Konzessivsatz","Nur einen einfachen Konditionalsatz mit normaler Verbstellung ohne Paar"],ans:"Verb-Erst-Konditionalsatz + sowohl...als auch + Konzessivsatz",hint:"Identify all three grammatical layers: a first-position conditional without 'wenn', an inclusive linking pair, and a concessive clause at the close."},
{type:"drag_fill",s:"{1} in allem war die Debatte {2} kontrovers, {3} produktiv.",blanks:{"1":"Alles","2":"zwar","3":"aber"},pool:["Alles","zwar","aber","Unter","Obgleich","und"],hint:"Three blanks: a summary expression, then a concession word, then the word introducing the counterargument. Think: overall / admittedly / however."},
{type:"match",pairs:[{trg:"Meiner Ansicht nach",src:"In my view"},{trg:"Auf den Punkt gebracht",src:"In a nutshell"},{trg:"Es steht au\u00dfer Frage",src:"It is beyond question"},{trg:"Alles in allem",src:"All in all"}]},
{type:"mc",q:"Was bedeutet 'ungeachtet'?",opts:["regardless of, irrespective of","all in all","to polarize","I am of the view that"],ans:"regardless of, irrespective of",hint:"un- (not) + geachtet (regarded). Takes genitive. Ignoring or disregarding."},
{type:"fb",s:"{1} der Minderheit.",a:["zugunsten"],opts:["ungeachtet","beipflichten","Alles in allem","zugunsten"],hint:"zu (to) + Gunsten (favor). A genitive preposition: for the benefit of.",sSrc:"In favor of the minority."},
{type:"mc",q:"Was bedeutet 'polarisieren'?",opts:["to counter that, it must be said that","to polarize","in favor of","I am of the view that"],ans:"to polarize",hint:"Near-identical in English. From Latin polus (pole). To push toward opposite extremes."},
{type:"fb",s:"Sollte man das Ergebnis {1}?",a:["relativieren"],opts:["Meiner Ansicht nach","angesichts","Ich bin der Auffassung, dass","relativieren"],hint:"From relativ (relative). To put into broader context, softening its impact.",sSrc:"Should one put the result into perspective?"},
{type:"mc",q:"Was bedeutet 'infrage stellen'?",opts:["contestable, challengeable","in a nutshell, to sum up","I am of the view that","to call into question, to challenge"],ans:"to call into question, to challenge",hint:"in + Frage (inquiry/doubt) + stellen (to place). To put something up for scrutiny."},
{type:"fb",s:"Darf ich Ihnen {1}?",a:["beipflichten"],opts:["Meiner Ansicht nach","beipflichten","entsch\\u00e4rfen","zur\\u00fcckweisen"],hint:"bei- (alongside) + pflichten (duty). To align with someone's expressed view.",sSrc:"May I agree with you?"},
{type:"mc",q:"Was bedeutet 'provozieren'?",opts:["to provoke","to defuse, to de-escalate","contestable, challengeable","in a nutshell, to sum up"],ans:"to provoke",hint:"Latin loan: provocare (to call forth). Sounds like its English equivalent."},
{type:"fb",s:"Ist das Urteil {1}?",a:["anfechtbar"],opts:["Ich bin der Auffassung, dass","Dem ist entgegenzuhalten, dass","polarisieren","anfechtbar"],hint:"anfechten (to contest) + -bar (able). A legal term: can be challenged in court.",sSrc:"Is the verdict contestable?"},
{type:"mc",q:"Die Regierung wird die Vorwürfe entschieden...?",opts:["zurückweisen","beipflichten","provozieren","forcieren"],ans:"zurückweisen",hint:"To reject or dismiss accusations. The prefix 'zurück' (back) + 'weisen' (to point/direct)."}
,{type:"match",pairs:[{trg:"der Politiker",src:"the politician (male)"},{trg:"die Politikerin",src:"the politician (female)"},{trg:"umstritten",src:"contested, disputed"},{trg:"kritisieren",src:"to criticize"},{trg:"\u00fcberzeugen",src:"to convince"},{trg:"unterst\u00fctzen",src:"to support"}]},{type:"match",pairs:[{trg:"das Gegenargument",src:"the counterargument"},{trg:"das Grundrecht",src:"the fundamental right"},{trg:"beschlie\u00dfen",src:"to decide, to pass (a law)"},{trg:"einwenden",src:"to object"},{trg:"verabschieden",src:"to pass (a law), to adopt"},{trg:"einerseits",src:"on the one hand"},{trg:"andererseits",src:"on the other hand"},{trg:"jedoch",src:"however, yet"},{trg:"hingegen",src:"on the contrary, in contrast"},{trg:"weder...noch",src:"neither...nor"},{trg:"je...desto",src:"the more...the more"},{trg:"teils...teils",src:"partly...partly"}]},{type:"match",pairs:[{trg:"die Minderheit",src:"the minority"},{trg:"pl\u00e4dieren",src:"to plead, to advocate"},{trg:"wenngleich",src:"even though, albeit"},{trg:"wenn auch",src:"even if, although"},{trg:"somit",src:"thus, therefore"},{trg:"die Pr\u00e4misse",src:"the premise"},{trg:"abw\u00e4gen",src:"to weigh up, to consider carefully"},{trg:"einr\u00e4umen",src:"to concede, to admit"},{trg:"vor allem",src:"above all, especially"},{trg:"insbesondere",src:"in particular, especially"},{trg:"allerdings",src:"however, though"},{trg:"zugegebenerma\u00dfen",src:"admittedly"}]},{type:"match",pairs:[{trg:"wohlgemerkt",src:"mind you, note well"},{trg:"das Stimmrecht",src:"right to vote"},{trg:"würde",src:"would (Konjunktiv II of werden)"},{trg:"im Vergleich zu",src:"in comparison to/with"},{trg:"\u00e4hnlich wie",src:"similar to"},{trg:"im Unterschied zu",src:"in contrast to, unlike"},{trg:"demgegen\u00fcber",src:"in contrast to that, on the other hand"},{trg:"gleicherma\u00dfen",src:"equally, in equal measure"},{trg:"ungeachtet dessen",src:"regardless of that, notwithstanding"},{trg:"der Zusammenschluss",src:"merger, union, alliance"},{trg:"die Ministerin",src:"minister (female)"},{trg:"die Strategie",src:"strategy"}]},{type:"match",pairs:[{trg:"der Vertreter",src:"representative"},{trg:"die Vertreterin",src:"representative (female)"},{trg:"verfassungsm\u00e4\u00dfig",src:"constitutional"},{trg:"entgegenwirken",src:"to counteract"},{trg:"Daraus ergibt sich",src:"from that follows"},{trg:"ungeachtet",src:"regardless of, irrespective of"},{trg:"infrage stellen",src:"to call into question, to challenge"},{trg:"Ich bin der Auffassung, dass",src:"I am of the view that"}]}]}
]};

export default UNIT_29;
